#include <iostream>
using namespace std;

int main() {
 int a, b;
 cout << Введите два числа: ";
 cin >> a >> b;
 int product = a * b;
 while(b != 0) {
 int temp = b;
 b = a % b;
 a = temp;
 }
 cout << "НОК: " << product / a << endl;
 return 0;
}"

