#include <iostream>
#include <string>
using namespace std;

int main() {
    // Целочисленные типы
    int integer = 42;
    short shortInt = 100;
    long longInt = 100000L;
    long long veryLong = 10000000000LL;

    // Вещественные типы
    float floating = 3.14f;
    double doublePrecision = 3.1415926535;
    long double longDouble = 3.141592653589793238L;

    // Символьные типы
    char character = 'A';
    wchar_t wideChar = L'Б';

    // Логический тип
    bool boolean = true;

    // Строка
    string text = \Hello C++";

    cout << "int: " << integer << endl;
    cout << "short: " << shortInt << endl;
    cout << "long: " << longInt << endl;
    cout << "long long: " << veryLong << endl;
    cout << "float: " << floating << endl;
    cout << "double: " << doublePrecision << endl;
    cout << "long double: " << longDouble << endl;
    cout << "char: " << character << endl;
    cout << "wchar_t: " << wideChar << endl;
    cout << "bool: " << boolalpha << boolean << endl;
    cout << "string: " << text << endl;

    return 0;
}"

#include <iostream>
#include <string>

int main() {
    // Целочисленные типы
    int integer = 42;
    short shortInt = 100;
    long longInt = 100000L;
    long long veryLong = 10000000000LL;

    // Вещественные типы
    float floating = 3.14f;
    double doublePrecision = 3.1415926535;
    long double longDouble = 3.141592653589793238L;

    // Символьные типы
    char character = 'A';
    wchar_t wideChar = L'Б';

    // Логический тип
    bool boolean = true;

    // Строка
    std::string text = \Hello C++";

    std::cout << "int: " << integer << std::endl;
    std::cout << "short: " << shortInt << std::endl;
    std::cout << "long: " << longInt << std::endl;
    std::cout << "long long: " << veryLong << std::endl;
    std::cout << "float: " << floating << std::endl;
    std::cout << "double: " << doublePrecision << std::endl;
    std::cout << "long double: " << longDouble << std::endl;
    std::cout << "char: " << character << std::endl;
    std::cout << "wchar_t: " << wideChar << std::endl;
    std::cout << "bool: " << std::boolalpha << boolean << std::endl;
    std::cout << "string: " << text << std::endl;

    return 0;
}"

#include <iostream>
using namespace std;

int main() {
    // Беззнаковые типы
    unsigned int positiveOnly = 4294967295U;
    unsigned short ushort = 65535;

    // Знаковые типы
    signed int signedInt = -2147483648;

    // Константы
    const int CONSTANT = 100;
    const double PI = 3.14159;

    // Volatile
    volatile int sensorValue = 0;

    cout << \unsigned int: " << positiveOnly << endl;
    cout << "unsigned short: " << ushort << endl;
    cout << "signed int: " << signedInt << endl;
    cout << "const int: " << CONSTANT << endl;
    cout << "const double: " << PI << endl;
    cout << "volatile int: " << sensorValue << endl;

    return 0;
}"

#include <iostream>

int main() {
    // Беззнаковые типы
    unsigned int positiveOnly = 4294967295U;
    unsigned short ushort = 65535;

    // Знаковые типы
    signed int signedInt = -2147483648;

    // Константы
    const int CONSTANT = 100;
    const double PI = 3.14159;

    // Volatile
    volatile int sensorValue = 0;

    std::cout << \unsigned int: " << positiveOnly << std::endl;
    std::cout << "unsigned short: " << ushort << std::endl;
    std::cout << "signed int: " << signedInt << std::endl;
    std::cout << "const int: " << CONSTANT << std::endl;
    std::cout << "const double: " << PI << std::endl;
    std::cout << "volatile int: " << sensorValue << std::endl;

    return 0;
}"

