code:
#include <iostream>
#include <vector>
using namespace std;

int main() {
    int x = 42;
    double y = 3.14;

    decltype(x) a = 100;        // a имеет тип int
    decltype(y) b = 2.71;       // b имеет тип double
    decltype(x + y) c = x + y;  // c имеет тип double

    vector<int> vec = {1, 2, 3};
    decltype(vec) anotherVec;   // anotherVec имеет тип vector<int>
    decltype(vec[0]) element = vec[0]; // element имеет тип int&

    cout << \a: " << a << " (type: int)" << endl;
    cout << "b: " << b << " (type: double)" << endl;
    cout << "c: " << c << " (type: double)" << endl;
    cout << "element: " << element << endl;

    return 0;
}"

#include <iostream>
#include <vector>

int main() {
    int x = 42;
    double y = 3.14;

    decltype(x) a = 100;        // a имеет тип int
    decltype(y) b = 2.71;       // b имеет тип double
    decltype(x + y) c = x + y;  // c имеет тип double

    std::vector<int> vec = {1, 2, 3};
    decltype(vec) anotherVec;   // anotherVec имеет тип vector<int>
    decltype(vec[0]) element = vec[0]; // element имеет тип int&

    std::cout << \a: " << a << " (type: int)" << std::endl;
    std::cout << "b: " << b << " (type: double)" << std::endl;
    std::cout << "c: " << c << " (type: double)" << std::endl;
    std::cout << "element: " << element << std::endl;

    return 0;
}"

#include <iostream>
#include <typeinfo>
using namespace std;

int main() {
    int integer = 42;
    double floating = 3.14;
    string text = \Hello";

    cout << "Type of integer: " << typeid(integer).name() << endl;
    cout << "Type of floating: " << typeid(floating).name() << endl;
    cout << "Type of text: " << typeid(text).name() << endl;

    // Сравнение типов
    if (typeid(integer) == typeid(int)) {
        cout << "integer is of type int" << endl;
    }

    if (typeid(floating) != typeid(int)) {
        cout << "floating is not of type int" << endl;
    }

    return 0;
}"

