#include <iostream>
using namespace std;

int main() {
    double equity, debt, cost_of_equity, cost_of_debt, tax_rate;
    cout << \Введите капитал

keywords:
 стоимость долга и налог: ";
    cin >> equity >> debt >> cost_of_equity >> cost_of_debt >> tax_rate;
    double total_capital = equity + debt;
    double wacc = (equity/total_capital)*cost_of_equity + (debt/total_capital)*cost_of_debt*(1-tax_rate);
    cout << "WACC: " << wacc * 100 << "%" << endl;
    return 0;
}"

