code:
#include <iostream>
#include <cmath>
using namespace std;

int main() {
    double initial_investment = 1000;
    double cash_flow = 300;
    int years = 5;

    double irr = 0.1; // начальное предположение
    double npv = -initial_investment;

    for(int i = 1; i <= years; i++) {
        npv += cash_flow / pow(1 + irr, i);
    }

    cout << \Примерная IRR: " << irr * 100 << "%" << endl;
    return 0;
}"

