#include <iostream>
#include <bitset>
using namespace std;

int main() {
    unsigned char a = 0b10101010; // 170
    unsigned char b = 0b11001100; // 204

    cout << \a = " << bitset<8>(a) << " (" << (int)a << ")" << endl;
    cout << "b = " << bitset<8>(b) << " (" << (int)b << ")" << endl;

    cout << "\nБитовые операции:" << endl;
    cout << "a & b = " << bitset<8>(a & b) << " (AND)" << endl;
    cout << "a | b = " << bitset<8>(a | b) << " (OR)" << endl;
    cout << "a ^ b = " << bitset<8>(a ^ b) << " (XOR)" << endl;
    cout << "~a = " << bitset<8>(~a) << " (NOT)" << endl;
    cout << "a << 1 = " << bitset<8>(a << 1) << " (LEFT SHIFT)" << endl;
    cout << "a >> 1 = " << bitset<8>(a >> 1) << " (RIGHT SHIFT)" << endl;

    return 0;
}"

#include <iostream>
#include <bitset>

int main() {
    unsigned char a = 0b10101010; // 170
    unsigned char b = 0b11001100; // 204

    std::cout << \a = " << std::bitset<8>(a) << " (" << (int)a << ")" << std::endl;
    std::cout << "b = " << std::bitset<8>(b) << " (" << (int)b << ")" << std::endl;

    std::cout << "\nБитовые операции:" << std::endl;
    std::cout << "a & b = " << std::bitset<8>(a & b) << " (AND)" << std::endl;
    std::cout << "a | b = " << std::bitset<8>(a | b) << " (OR)" << std::endl;
    std::cout << "a ^ b = " << std::bitset<8>(a ^ b) << " (XOR)" << std::endl;
    std::cout << "~a = " << std::bitset<8>(~a) << " (NOT)" << std::endl;
    std::cout << "a << 1 = " << std::bitset<8>(a << 1) << " (LEFT SHIFT)" << std::endl;
    std::cout << "a >> 1 = " << std::bitset<8>(a >> 1) << " (RIGHT SHIFT)" << std::endl;

    return 0;
}"

#include <iostream>
using namespace std;

int main() {
    double real1 = 4, imag1 = 3; // 4 + 3i
    double real2 = 1, imag2 = 2; // 1 + 2i

    double denominator = real2*real2 + imag2*imag2;
    double real = (real1*real2 + imag1*imag2) / denominator;
    double imag = (imag1*real2 - real1*imag2) / denominator;

    cout << \Результат деления: " << real << " + " << imag << "i" << endl;
    return 0;
}"

