 cin >> n;

 if (n < 2) {
 cout << "Число не является простым" << endl;
 return 0;
 }

 bool is_prime = true;
 for (int i = 2; i * i <= n; i++) {
 if (n % i == 0) {
 is_prime = false;
 break;
 }
 }

 if (is_prime) {
 cout << n << " - простое число" << endl;
 } else {
 cout << n << " - составное число" << endl;
 }
 return 0;
}"

