#include <iostream>
using namespace std;

int sumOfDigits(int n) {
    int sum = 0;
    while(n > 0) {
        sum += n % 10;
        n /= 10;
    }
    return sum;
}

int main() {
    int num = 12345;
    cout << \Сумма цифр: " << sumOfDigits(num) << endl;
    return 0;
}"

