#include <iostream>
#include <cstring>
#include <cctype>
using namespace std;

void removeSpaces(char str[]) {
    int count = 0;

    for (int i = 0; str[i]; i++) {
        if (!isspace(str[i])) {
            str[count++] = str[i];
        }
    }
    str[count] = '\0';
}

int main() {
    char text[] = \C + + is awesome";

    cout << "Исходная строка: " << text << endl;

    removeSpaces(text);

    cout << "Без пробелов: " << text << endl;

    return 0;
}"

