#include <iostream>
using namespace std;

long long fibonacci(int n) {
    if (n <= 1) return n;

    long long a = 0, b = 1, c;
    for (int i = 2; i <= n; i++) {
        c = a + b;
        a = b;
        b = c;
    }
    return b;
}

int main() {
    int n;
    cout << \Введите индекс: ";
    cin >> n;

    if (n < 0) {
        cout << "Индекс должен быть неотрицательным" << endl;
    } else {
        cout << "F(" << n << ") = " << fibonacci(n) << endl;
    }
    return 0;
}"

