#include <iostream>
#include <cstring>
#include <cctype>
using namespace std;

int countWords(char str[]) {
    int count = 0;
    bool inWord = false;

    for (int i = 0; i < strlen(str); i++) {
        if (isalpha(str[i]) && !inWord) {
            count++;
            inWord = true;
        } else if (isspace(str[i])) {
            inWord = false;
        }
    }

    return count;
}

int main() {
    char str[] = \Hello World from C++ Programming";

    cout << "Строка: " << str << endl;
    cout << "Количество слов: " << countWords(str) << endl;

    return 0;
}"

#include <iostream>
#include <cstring>
#include <cctype>

int countWords(char str[]) {
    int count = 0;
    bool inWord = false;

    for (int i = 0; i < std::strlen(str); i++) {
        if (std::isalpha(str[i]) && !inWord) {
            count++;
            inWord = true;
        } else if (std::isspace(str[i])) {
            inWord = false;
        }
    }

    return count;
}

int main() {
    char str[] = \Hello World from C++ Programming";

    std::cout << "Строка: " << str << std::endl;
    std::cout << "Количество слов: " << countWords(str) << std::endl;

    return 0;
}"

