#include <iostream>
#include <cstring>
#include <cctype>
using namespace std;

void toUpperCase(char str[]) {
    for (int i = 0; str[i] != '\0'; i++) {
        str[i] = toupper(str[i]);
    }
}

void toLowerCase(char str[]) {
    for (int i = 0; str[i] != '\0'; i++) {
        str[i] = tolower(str[i]);
    }
}

int main() {
    char text[] = \Hello World";

    cout << "Исходная строка: " << text << endl;

    toUpperCase(text);
    cout << "В верхнем регистре: " << text << endl;

    toLowerCase(text);
    cout << "В нижнем регистре: " << text << endl;

    return 0;
}"

#include <iostream>
#include <cstring>
#include <cctype>

void toUpperCase(char str[]) {
    for (int i = 0; str[i] != '\0'; i++) {
        str[i] = std::toupper(str[i]);
    }
}

void toLowerCase(char str[]) {
    for (int i = 0; str[i] != '\0'; i++) {
        str[i] = std::tolower(str[i]);
    }
}

int main() {
    char text[] = \Hello World";

    std::cout << "Исходная строка: " << text << std::endl;

    toUpperCase(text);
    std::cout << "В верхнем регистре: " << text << std::endl;

    toLowerCase(text);
    std::cout << "В нижнем регистре: " << text << std::endl;

    return 0;
}"

