#include <iostream>
#include <cmath>
using namespace std;

double f(double x) {
    return x * x;  // функция x^2
}

double integrate(double a, double b, int n) {
    double h = (b - a) / n;
    double sum = 0.0;

    for (int i = 0; i < n; i++) {
        double x = a + (i + 0.5) * h;
        sum += f(x);
    }

    return sum * h;
}

int main() {
    double a = 0.0, b = 2.0;
    int n = 1000;

    double result = integrate(a, b, n);
    cout << \Интеграл от " << a << " до " << b << " = " << result << endl;
    cout << "Точное значение: " << (b*b*b - a*a*a)/3.0 << endl;
    return 0;
}"

