#include <iostream>
using namespace std;

int reverseNumber(int n) {
    int reversed = 0;
    while (n != 0) {
        reversed = reversed * 10 + n % 10;
        n /= 10;
    }
    return reversed;
}

int main() {
    int number = 12345;
    cout << \Исходное число: " << number << endl;
    cout << "Перевернутое число: " << reverseNumber(number) << endl;
    return 0;
}"

