#include <iostream>
using namespace std;

int main() {
    int value = 42;
    int* ptr = &value;
    int** ptrToPtr = &ptr;

    cout << \Прямой доступ:" << endl;
    cout << "value = " << value << endl;
    cout << "*ptr = " << *ptr << endl;
    cout << "**ptrToPtr = " << **ptrToPtr << endl;

    cout << "\nЦепочка адресов:" << endl;
    cout << "&value = " << &value << endl;
    cout << "ptr = " << ptr << endl;
    cout << "&ptr = " << &ptr << endl;
    cout << "ptrToPtr = " << ptrToPtr << endl;

    // Изменение через двойное разыменование
    **ptrToPtr = 100;
    cout << "\nПосле **ptrToPtr = 100:" << endl;
    cout << "value = " << value << endl;

    return 0;
}"

