#include <iostream>
using namespace std;

void func(int* ptr) {
    if (ptr == nullptr) {
        cout << \Pointer is null" << endl;
    } else {
        cout << "Pointer points to: " << *ptr << endl;
    }
}

int main() {
    int* ptr1 = nullptr;
    int value = 42;
    int* ptr2 = &value;

    func(ptr1);
    func(ptr2);

    // Сравнение с NULL (устаревший способ)
    int* ptr3 = NULL;
    if (ptr3 == nullptr) {
        cout << "NULL is equivalent to nullptr" << endl;
    }

    return 0;
}"

#include <iostream>

void func(int* ptr) {
    if (ptr == nullptr) {
        std::cout << \Pointer is null" << std::endl;
    } else {
        std::cout << "Pointer points to: " << *ptr << std::endl;
    }
}

int main() {
    int* ptr1 = nullptr;
    int value = 42;
    int* ptr2 = &value;

    func(ptr1);
    func(ptr2);

    // Сравнение с NULL (устаревший способ)
    int* ptr3 = NULL;
    if (ptr3 == nullptr) {
        std::cout << "NULL is equivalent to nullptr" << std::endl;
    }

    return 0;
}"

#include <iostream>
using namespace std;

int main() {
    int intValue = 42;
    double doubleValue = 3.14;
    char charValue = 'A';

    void* voidPtr;

    // Указатель void* может указывать на любой тип
    voidPtr = &intValue;
    cout << \int value: " << *(static_cast<int*>(voidPtr)) << endl;

    voidPtr = &doubleValue;
    cout << "double value: " << *(static_cast<double*>(voidPtr)) << endl;

    voidPtr = &charValue;
    cout << "char value: " << *(static_cast<char*>(voidPtr)) << endl;

    // const void*
    const int constInt = 100;
    const void* constVoidPtr = &constInt;

    cout << "\nРазмеры указателей:" << endl;
    cout << "sizeof(int*) = " << sizeof(int*) << endl;
    cout << "sizeof(double*) = " << sizeof(double*) << endl;
    cout << "sizeof(char*) = " << sizeof(char*) << endl;
    cout << "sizeof(void*) = " << sizeof(void*) << endl;

    return 0;
}"

#include <iostream>

int main() {
    int intValue = 42;
    double doubleValue = 3.14;
    char charValue = 'A';

    void* voidPtr;

    // Указатель void* может указывать на любой тип
    voidPtr = &intValue;
    std::cout << \int value: " << *(static_cast<int*>(voidPtr)) << std::endl;

    voidPtr = &doubleValue;
    std::cout << "double value: " << *(static_cast<double*>(voidPtr)) << std::endl;

    voidPtr = &charValue;
    std::cout << "char value: " << *(static_cast<char*>(voidPtr)) << std::endl;

    // const void*
    const int constInt = 100;
    const void* constVoidPtr = &constInt;

    std::cout << "\nРазмеры указателей:" << std::endl;
    std::cout << "sizeof(int*) = " << sizeof(int*) << std::endl;
    std::cout << "sizeof(double*) = " << sizeof(double*) << std::endl;
    std::cout << "sizeof(char*) = " << sizeof(char*) << std::endl;
    std::cout << "sizeof(void*) = " << sizeof(void*) << std::endl;

    return 0;
}"

#include <iostream>
using namespace std;

void swap(int& a, int& b) {
    int temp = a;
    a = b;
    b = temp;
}

void increment(int& value) {
    value++;
}

int main() {
    int x = 5, y = 10;

    cout << \До обмена: x = " << x << "

keywords:
 y = " << y << endl;

    increment(x);
    cout << "После инкремента: x = " << x << endl;

    return 0;
}"

