code:
#include <iostream>
using namespace std;

int main() {
    int original = 42;
    int& ref = original;  // ссылка на original

    cout << \original: " << original << endl;
    cout << "ref: " << ref << endl;
    cout << "&original: " << &original << endl;
    cout << "&ref: " << &ref << endl;

    // Изменение через ссылку
    ref = 100;
    cout << "\nПосле изменения ref:" << endl;
    cout << "original: " << original << endl;
    cout << "ref: " << ref << endl;

    // Ссылка как псевдоним
    int& alias = ref;
    alias = 200;
    cout << "\nПосле изменения alias:" << endl;
    cout << "original: " << original << endl;

    return 0;
}"

#include <iostream>

int main() {
