    std::cout << "&original: " << &original << std::endl;
    std::cout << "&ref: " << &ref << std::endl;

    // Изменение через ссылку
    ref = 100;
    std::cout << "\nПосле изменения ref:" << std::endl;
    std::cout << "original: " << original << std::endl;
    std::cout << "ref: " << ref << std::endl;

    // Ссылка как псевдоним
    int& alias = ref;
    alias = 200;
    std::cout << "\nПосле изменения alias:" << std::endl;
    std::cout << "original: " << original << std::endl;

    return 0;
}"

