code:
#include <iostream>
#include <vector>
using namespace std;

int main() {
    vector<int> numbers = {1, 2, 3, 4, 5};

    cout << \Исходный вектор: ";
    for (int num : numbers) {
        cout << num << " ";
    }
    cout << endl;

    // Изменение элементов через ссылку
    cout << "Удвоение элементов через ссылку:" << endl;
    for (int& num : numbers) {
        num *= 2;
    }

    cout << "После удвоения: ";
    for (int num : numbers) {
        cout << num << " ";
    }
    cout << endl;

    // Эффективный доступ без копирования
    vector<string> words = {"apple"

topic:
 "cherry"};
    cout << "\nЭффективный доступ к строкам:" << endl;
    for (const string& word : words) {
        cout << word << " (длина: " << word.length() << ")" << endl;
    }

    return 0;
}"

