#include <iostream>
#include <vector>
using namespace std;

// Плохой пример - возврат ссылки на локальную переменную
// int& badFunction() {
//     int x = 10;
//     return x; // ОПАСНО!
// }

// Хороший пример - возврат ссылки на элемент массива
int& getElement(vector<int>& arr, int index) {
    return arr[index];
}

// Возврат ссылки на статическую переменную
int& getCounter() {
    static int counter = 0;
    return counter;
}

int main() {
    vector<int> numbers = {10, 20, 30, 40, 50};

    cout << \Исходный массив: ";
    for (int num : numbers) {
        cout << num << " ";
    }
    cout << endl;

    // Изменение через возвращаемую ссылку
    getElement(numbers

style:
 2) = 100;
    cout << "После изменения: ";
    for (int num : numbers) {
        cout << num << " ";
    }
    cout << endl;

    // Использование счетчика
    getCounter() = 5;
    cout << "Счетчик: " << getCounter() << endl;

    getCounter()++;
    cout << "После инкремента: " << getCounter() << endl;

    return 0;
}"

