#include <iostream>
using namespace std;

int main() {
    int size = 5;
    int* dynamicArray = new int[size];

    // Заполнение массива
    for (int i = 0; i < size; i++) {
        dynamicArray[i] = (i + 1) * 10;
    }

    cout << \Динамический массив:" << endl;
    for (int i = 0; i < size; i++) {
        cout << "dynamicArray[" << i << "] = " << *(dynamicArray + i) << endl;
    }

    // Освобождение памяти
    delete[] dynamicArray;

    return 0;
}"

