code:
#include <iostream>
#include <string>
using namespace std;

string rot13(const string& text) {
    string result;

    for(char c : text) {
        if(isalpha(c)) {
            char base = isupper(c) ? 'A' : 'a';
            result += (c - base + 13) % 26 + base;
        } else {
            result += c;
        }
    }

    return result;
}

int main() {
    string text = \Hello World";
    string encoded = rot13(text);
    string decoded = rot13(encoded);

    cout << "Исходный: " << text << endl;
    cout << "ROT13: " << encoded << endl;
    cout << "Обратно: " << decoded << endl;
    return 0;
}"

#include <iostream>
#include <string>

std::string rot13(const std::string& text) {
    std::string result;

    for(char c : text) {
        if(std::isalpha(c)) {
            char base = std::isupper(c) ? 'A' : 'a';
            result += (c - base + 13) % 26 + base;
        } else {
            result += c;
        }
    }

    return result;
}

int main() {
    std::string text = \Hello World";
    std::string encoded = rot13(text);
    std::string decoded = rot13(encoded);

    std::cout << "Исходный: " << text << std::endl;
    std::cout << "ROT13: " << encoded << std::endl;
    std::cout << "Обратно: " << decoded << std::endl;
    return 0;
}"

#include <iostream>
#include <string>
using namespace std;

bool isPalindrome(const string& str) {
    int left = 0, right = str.length() - 1;
    while(left < right) {
        if(str[left] != str[right]) return false;
        left++;
        right--;
    }
    return true;
}

int main() {
    string str = acecar";
    cout << str << (isPalindrome(str) ? " - палиндром" : " - не палиндром") << endl;
    return 0;
}"

#include <iostream>
#include <string>

bool isPalindrome(const std::string& str) {
    int left = 0, right = str.length() - 1;
    while(left < right) {
        if(str[left] != str[right]) return false;
        left++;
        right--;
    }
    return true;
}

int main() {
    std::string str = acecar";
    std::cout << str << (isPalindrome(str) ? " - палиндром" : " - не палиндром") << std::endl;
    return 0;
}"

