#include <iostream>
#include <cmath>
using namespace std;

struct Point {
    double x, y;

    // Конструктор
    Point(double x_val = 0, double y_val = 0) : x(x_val), y(y_val) {}

    // Методы
    double distanceToOrigin() const {
        return sqrt(x * x + y * y);
