class Cache {
    map<string, pair<string, time_t>> data;
public:
    void set(string key, string value, int ttl = 60) {
        data[key] = {value, time(nullptr) + ttl};
    }
    string get(string key) {
        auto it = data.find(key);
        if(it != data.end() && it->second.second > time(nullptr)) {
            return it->second.first;
        }
        return \";
    }
};

