#include <iostream>
#include <ctime>
using namespace std;

union ButtonState {
    struct {
        bool pressed;
        time_t press_time;
    } state;
    char raw_data[sizeof(state)];
};

int main() {
    ButtonState btn;

    btn.state.pressed = true;
    btn.state.press_time = time(nullptr);

    cout << \Состояние кнопки:" << endl;
    cout << "Нажата: " << (btn.state.pressed ? "Да" : "Нет") << endl;
    cout << "Время нажатия: " << ctime(&btn.state.press_time);

    cout << "\nБайтовое представление: ";
    for (size_t i = 0; i < sizeof(btn.raw_data); i++) {
        cout << (int)btn.raw_data[i] << " ";
    }
    cout << endl;

    return 0;
}"

