#include <iostream>
#include <cmath>
using namespace std;

union FloatWithAbs {
    float value;
    struct {
        float original;
        float absolute;
    } pair;
};

int main() {
    FloatWithAbs fa;
    fa.value = -3.14f;

    cout << \Оригинальное значение: " << fa.value << endl;

    float abs_value = fabs(fa.value);
    fa.pair.original = fa.value;
    fa.pair.absolute = abs_value;

    cout << "\nПосле помещения в структуру:" << endl;
    cout << "Оригинальное: " << fa.pair.original << endl;
    cout << "Абсолютное: " << fa.pair.absolute << endl;

    cout << "\nЗначение через value: " << fa.value << " (мусор)" << endl;

    return 0;
}"

