#include <iostream>
#include <cstdint>
using namespace std;

union IPv4Address {
    uint32_t address;
    struct {
        uint8_t octet4;
        uint8_t octet3;
        uint8_t octet2;
        uint8_t octet1;
    } octets;
};

int main() {
    IPv4Address ip;
    ip.address = 0xC0A80101; // 192.168.1.1 в шестнадцатеричном формате

    cout << \IP адрес в десятичном виде: ";
    cout << (int)ip.octets.octet1 << "." << (int)ip.octets.octet2 << "."
         << (int)ip.octets.octet3 << "." << (int)ip.octets.octet4 << endl;

    cout << "\nПроверка разделяемой памяти:" << endl;
    cout << "address = 0x" << hex << ip.address << dec << endl;
    cout << "Размер union: " << sizeof(IPv4Address) << " байт" << endl;

    return 0;
}"

