    cout << \Число: " << fa.value << endl;
    cout << "\nБитовое представление:" << endl;
    cout << "Знак: " << fa.parts.sign << " (" << (fa.parts.sign ? "отрицательное" : "положительное") << ")" << endl;
    cout << "Экспонента: " << fa.parts.exponent << " (смещенная)" << endl;
    cout << "Мантисса: " << fa.parts.mantissa << endl;

    cout << "\nДвоичное представление мантиссы: " 
         << bitset<23>(fa.parts.mantissa) << endl;

    return 0;
}"

