#include <iostream>
#include <cstdint>
using namespace std;

union EndianConverter {
    uint32_t value;
    uint8_t bytes[4];
};

uint32_t swap_endian(uint32_t val) {
    EndianConverter conv;
    conv.value = val;

    uint8_t temp = conv.bytes[0];
    conv.bytes[0] = conv.bytes[3];
    conv.bytes[3] = temp;

    temp = conv.bytes[1];
    conv.bytes[1] = conv.bytes[2];
    conv.bytes[2] = temp;

    return conv.value;
}

int main() {
    EndianConverter conv;
    conv.value = 0xAABBCCDD;

    cout << \Оригинальное значение: 0x" << hex << conv.value << dec << endl;
    cout << "\nПорядок байтов в памяти:" << endl;
    for (int i = 0; i < 4; i++) {
        cout << "Байт[" << i << "] = 0x" << hex << (int)conv.bytes[i] << dec << endl;
    }

    uint32_t swapped = swap_endian(conv.value);
    cout << "\nПосле смены endianness: 0x" << hex << swapped << dec << endl;

    conv.value = 1;
    cout << "\nПроверка порядка байтов системы:" << endl;
    cout << "Младший байт первый (little-endian)? " << (conv.bytes[0] == 1 ? "Да" : "Нет") << endl;

    return 0;
}"

