#include <iostream>
using namespace std;

union Color {
    uint32_t rgba;
    struct {
        uint8_t b;
        uint8_t g;
        uint8_t r;
        uint8_t a;
    };

    Color() : rgba(0) {}
    Color(uint8_t r, uint8_t g, uint8_t b, uint8_t a = 255) {
        this->r = r;
        this->g = g;
        this->b = b;
        this->a = a;
    }
};

int main() {
    Color white(255, 255, 255);
    Color red(255, 0, 0);
    Color blue(0, 0, 255, 128); // Полупрозрачный синий

    cout << \Цвета в формате RGBA:" << endl;
    cout << "Белый: 0x" << hex << white.rgba << dec << endl;
    cout << "Красный: R=" << (int)red.r << " G=" << (int)red.g 
         << " B=" << (int)red.b << endl;
    cout << "Полупрозрачный синий: Alpha=" << (int)blue.a << "%" << endl;

    // Изменение через одно поле влияет на все
    cout << "\nДемонстрация разделяемой памяти:" << endl;
    Color test;
    test.rgba = 0x12345678;
    cout << "RGBA=0x" << hex << test.rgba << dec << endl;
    cout << "R=0x" << hex << (int)test.r << " G=0x" << (int)test.g 
         << " B=0x" << (int)test.b << " A=0x" << (int)test.a << dec << endl;

    return 0;
}"

