#include <iostream>
#include <string>
#include <cstring>
using namespace std;

struct Variant {
    enum Type { INT, DOUBLE, STRING } type;

    union {
        int intValue;
        double doubleValue;
        char stringValue[32];
    };

    // Конструкторы
    Variant(int val) : type(INT) { intValue = val; }
    Variant(double val) : type(DOUBLE) { doubleValue = val; }
    Variant(const string& str) : type(STRING) {
        strncpy(stringValue, str.c_str(), 31);
        stringValue[31] = '\0';
    }

    void print() const {
        switch (type) {
            case INT: 
                cout << \int: " << intValue; 
                break;
            case DOUBLE: 
                cout << "double: " << doubleValue; 
                break;
            case STRING: 
                cout << "string: \"" << stringValue << "\""; 
                break;
        }
        cout << endl;
    }
};

int main() {
    Variant v1(42);
    Variant v2(3.14);
    Variant v3("Hello");

    cout << "Значения Variant:" << endl;
    v1.print();
    v2.print();
    v3.print();

    cout << "\nРазмер Variant: " << sizeof(Variant) << " байт" << endl;

    return 0;
}"

