#include <arpa/inet.h>

#pragma pack(push, 1)
union NetworkPacket {
    struct {
        uint8_t dest_mac[6];
        uint8_t src_mac[6];
        uint16_t ethertype;
    } ethernet;

    struct {
        uint8_t version_ihl;
        uint8_t tos;
        uint16_t total_length;
        uint16_t identification;
        uint16_t flags_fragment;
        uint8_t ttl;
        uint8_t protocol;
        uint16_t checksum;
        uint32_t src_ip;
        uint32_t dest_ip;
    } ip;

    uint8_t raw_data[60];
};
#pragma pack(pop)

int main() {
    NetworkPacket packet;
    std::memset(&packet, 0, sizeof(packet));

    packet.ethernet.ethertype = 0x0800;
    packet.ip.version_ihl = 0x45;
    packet.ip.total_length = htons(60);
    packet.ip.ttl = 64;
    packet.ip.protocol = 6;
    packet.ip.src_ip = 0xC0A80101;
    packet.ip.dest_ip = 0xC0A80102;

    std::cout << \Размер пакета: " << sizeof(packet) << " байт" << std::endl;
    std::cout << "Ethertype: 0x" << std::hex << packet.ethernet.ethertype << std::dec << std::endl;
    std::cout << "IP версия: " << (packet.ip.version_ihl >> 4) << std::endl;
    std::cout << "Протокол: " << (int)packet.ip.protocol << std::endl;

    return 0;
}"

#include <iostream>
#include <cstdint>
using namespace std;

union CompactFlags {
    uint8_t byte;
    struct {
        uint8_t flag1 : 1;
        uint8_t flag2 : 1;
        uint8_t flag3 : 1;
        uint8_t flag4 : 1;
        uint8_t flag5 : 1;
        uint8_t flag6 : 1;
        uint8_t flag7 : 1;
        uint8_t flag8 : 1;
    } bits;

    void print_bits() const {
        cout << \Биты: ";
        cout << bits.flag8 << bits.flag7 << bits.flag6 << bits.flag5
             << bits.flag4 << bits.flag3 << bits.flag2 << bits.flag1;
        cout << " (байт: 0x" << hex << (int)byte << dec << ")" << endl;
    }
};

int main() {
    CompactFlags flags;
    flags.byte = 0;

    flags.bits.flag1 = 1;
    flags.bits.flag4 = 1;
    flags.bits.flag8 = 1;

    cout << "После установки флагов 1

style:
 4 и 8:" << endl;
    flags.print_bits();

    flags.byte = 0xAA;
    cout << "\nПосле установки байта 0xAA:" << endl;
    flags.print_bits();

    cout << "\nПроверка флагов:" << endl;
    cout << "flag1: " << (flags.bits.flag1 ? "true" : "false") << endl;
    cout << "flag2: " << (flags.bits.flag2 ? "true" : "false") << endl;

    cout << "\nЭкономия памяти:" << endl;
    cout << "Размер CompactFlags: " << sizeof(CompactFlags) << " байт" << endl;
    cout << "8 отдельных bool заняли бы: " << 8 * sizeof(bool) << " байт" << endl;

    return 0;
}"

