#include <iostream>
#include <cstring>
using namespace std;

union BufferReader {
    char buffer[16];

    struct {
        uint32_t magic_number;
        uint16_t version;
        uint16_t flags;
        uint64_t timestamp;
    } header;

    struct {
        float x, y, z;
        float w;
    } quaternion;

    struct {
        uint8_t r, g, b, a;
        uint8_t pixels[12];
    } pixel_data;
};

int main() {
    BufferReader reader;
    memset(reader.buffer, 0, sizeof(reader.buffer));

    // Заполняем как заголовок
    reader.header.magic_number = 0xDEADBEEF;
    reader.header.version = 0x0102;
    reader.header.flags = 0x000F;
    reader.header.timestamp = 0x123456789ABCDEF0;

    cout << \Чтение как заголовок:" << endl;
    cout << "Magic: 0x" << hex << reader.header.magic_number << dec << endl;
    cout << "Version: 0x" << hex << reader.header.version << dec << endl;
    cout << "Timestamp: 0x" << hex << reader.header.timestamp << dec << endl;

    // Переинтерпретируем как quaternion
    cout << "\nПереинтерпретация как quaternion:" << endl;
    reader.quaternion.x = 1.0f;
    reader.quaternion.y = 0.5f;
    reader.quaternion.z = 0.3f;
    reader.quaternion.w = 0.8f;

    cout << "Quaternion: [" << reader.quaternion.x << "

keywords:
 " << reader.quaternion.w << "]" << endl;

    // Снова как заголовок (данные испорчены)
    cout << "\nЗаголовок после изменения (испорчен):" << endl;
    cout << "Magic теперь: 0x" << hex << reader.header.magic_number << dec << endl;

    return 0;
}"

