#include <iostream>
#include <string>
#include <typeinfo>
using namespace std;

struct Variant {
    enum Type { INT, FLOAT, STRING, INVALID } type;

    union {
        int int_val;
        float float_val;
        char str_val[32];
    };

    Variant() : type(INVALID) {}
    Variant(int v) : type(INT) { int_val = v; }
    Variant(float v) : type(FLOAT) { float_val = v; }
    Variant(const string& s) : type(STRING) {
        strncpy(str_val, s.c_str(), 31);
        str_val[31] = '\0';
    }

    template<typename T>
    bool is() const {
        if constexpr (is_same_v<T, int>) return type == INT;
        else if constexpr (is_same_v<T, float>) return type == FLOAT;
        else if constexpr (is_same_v<T, string>) return type == STRING;
        return false;
    }

    template<typename T>
    T get() const {
        if (is<T>()) {
            if constexpr (is_same_v<T, int>) return int_val;
            else if constexpr (is_same_v<T, float>) return float_val;
            else if constexpr (is_same_v<T, string>) return string(str_val);
        }
        throw runtime_error(\Неверный тип");
    }
};

int main() {
    Variant v1 = 42;
    Variant v2 = 3.14f;
    Variant v3 = string("Hello");

    cout << "Проверка типов:" << endl;
    cout << "v1 is int: " << boolalpha << v1.is<int>() << endl;
    cout << "v2 is float: " << v2.is<float>() << endl;
    cout << "v3 is string: " << v3.is<string>() << endl;

    cout << "\nЗначения:" << endl;
    cout << "v1: " << v1.get<int>() << endl;
    cout << "v2: " << v2.get<float>() << endl;
    cout << "v3: " << v3.get<string>() << endl;

    try {
        v1.get<float>(); // Это выбросит исключение
    } catch (const exception& e) {
        cout << "\nОшибка: " << e.what() << endl;
    }

    return 0;
}"

#include <iostream>
#include <string>
#include <cstring>
#include <type_traits>
#include <stdexcept>

struct Variant {
    enum Type { INT, FLOAT, STRING, INVALID } type;

    union {
        int int_val;
        float float_val;
        char str_val[32];
    };

    Variant() : type(INVALID) {}
    Variant(int v) : type(INT) { int_val = v; }
    Variant(float v) : type(FLOAT) { float_val = v; }
    Variant(const std::string& s) : type(STRING) {
        std::strncpy(str_val, s.c_str(), 31);
        str_val[31] = '\0';
    }

    template<typename T>
    bool is() const {
        if constexpr (std::is_same_v<T, int>) return type == INT;
        else if constexpr (std::is_same_v<T, float>) return type == FLOAT;
        else if constexpr (std::is_same_v<T, std::string>) return type == STRING;
        return false;
    }

    template<typename T>
    T get() const {
        if (is<T>()) {
            if constexpr (std::is_same_v<T, int>) return int_val;
            else if constexpr (std::is_same_v<T, float>) return float_val;
            else if constexpr (std::is_same_v<T, std::string>) return std::string(str_val);
        }
        throw std::runtime_error(\Неверный тип");
    }
};

int main() {
    Variant v1 = 42;
    Variant v2 = 3.14f;
    Variant v3 = std::string("Hello");

    std::cout << "Проверка типов:" << std::endl;
    std::cout << "v1 is int: " << std::boolalpha << v1.is<int>() << std::endl;
    std::cout << "v2 is float: " << v2.is<float>() << std::endl;
    std::cout << "v3 is string: " << v3.is<std::string>() << std::endl;

    std::cout << "\nЗначения:" << std::endl;
    std::cout << "v1: " << v1.get<int>() << std::endl;
    std::cout << "v2: " << v2.get<float>() << std::endl;
    std::cout << "v3: " << v3.get<std::string>() << std::endl;

    try {
        v1.get<float>();
    } catch (const std::exception& e) {
        std::cout << "\nОшибка: " << e.what() << std::endl;
    }

    return 0;
}"

