    } data;

    Shape(double r) : type(CIRCLE) { data.circle.radius = r; }
    Shape(double w, double h) : type(RECTANGLE) {
        data.rectangle.width = w;
        data.rectangle.height = h;
    }
    Shape(double a, double b, double c) : type(TRIANGLE) {
        data.triangle.a = a;
        data.triangle.b = b;
        data.triangle.c = c;
    }

    double area() const {
        switch (type) {
            case CIRCLE: 
                return M_PI * data.circle.radius * data.circle.radius;
            case RECTANGLE: 
                return data.rectangle.width * data.rectangle.height;
            case TRIANGLE: {
                double p = (data.triangle.a + data.triangle.b + data.triangle.c) / 2;
                return sqrt(p * (p - data.triangle.a) * (p - data.triangle.b) * (p - data.triangle.c));
            }
            default: return 0;
        }
    }

    double perimeter() const {
        switch (type) {
            case CIRCLE: return 2 * M_PI * data.circle.radius;
            case RECTANGLE: return 2 * (data.rectangle.width + data.rectangle.height);
            case TRIANGLE: return data.triangle.a + data.triangle.b + data.triangle.c;
            default: return 0;
        }
    }
};

int main() {
    Shape circle(5.0);
    Shape rectangle(4.0, 6.0);
    Shape triangle(3.0, 4.0, 5.0);

    cout << \Геометрические фигуры:" << endl;
    cout << "\nКруг (радиус=5):" << endl;
    cout << "Площадь: " << circle.area() << endl;
    cout << "Периметр: " << circle.perimeter() << endl;

    cout << "\nПрямоугольник (4x6):" << endl;
    cout << "Площадь: " << rectangle.area() << endl;
    cout << "Периметр: " << rectangle.perimeter() << endl;

    cout << "\nТреугольник (3-4-5):" << endl;
    cout << "Площадь: " << triangle.area() << endl;
    cout << "Периметр: " << triangle.perimeter() << endl;

    cout << "\nРазмер структуры Shape: " << sizeof(Shape) << " байт" << endl;

    return 0;
}"

#include <iostream>
#include <cmath>

struct Shape {
    enum Type { CIRCLE, RECTANGLE, TRIANGLE } type;

    union {
        struct { double radius; } circle;
        struct { double width, height; } rectangle;
        struct { double a, b, c; } triangle;
    } data;

    Shape(double r) : type(CIRCLE) { data.circle.radius = r; }
    Shape(double w, double h) : type(RECTANGLE) {
        data.rectangle.width = w;
        data.rectangle.height = h;
    }
    Shape(double a, double b, double c) : type(TRIANGLE) {
        data.triangle.a = a;
        data.triangle.b = b;
        data.triangle.c = c;
    }

    double area() const {
        switch (type) {
            case CIRCLE: 
                return M_PI * data.circle.radius * data.circle.radius;
            case RECTANGLE: 
                return data.rectangle.width * data.rectangle.height;
            case TRIANGLE: {
                double p = (data.triangle.a + data.triangle.b + data.triangle.c) / 2;
                return std::sqrt(p * (p - data.triangle.a) * (p - data.triangle.b) * (p - data.triangle.c));
            }
            default: return 0;
        }
    }

    double perimeter() const {
        switch (type) {
            case CIRCLE: return 2 * M_PI * data.circle.radius;
            case RECTANGLE: return 2 * (data.rectangle.width + data.rectangle.height);
            case TRIANGLE: return data.triangle.a + data.triangle.b + data.triangle.c;
            default: return 0;
        }
    }
};

int main() {
    Shape circle(5.0);
    Shape rectangle(4.0, 6.0);
    Shape triangle(3.0, 4.0, 5.0);

    std::cout << \Геометрические фигуры:" << std::endl;
    std::cout << "\nКруг (радиус=5):" << std::endl;
    std::cout << "Площадь: " << circle.area() << std::endl;
    std::cout << "Периметр: " << circle.perimeter() << std::endl;

    std::cout << "\nПрямоугольник (4x6):" << std::endl;
    std::cout << "Площадь: " << rectangle.area() << std::endl;
    std::cout << "Периметр: " << rectangle.perimeter() << std::endl;

    std::cout << "\nТреугольник (3-4-5):" << std::endl;
    std::cout << "Площадь: " << triangle.area() << std::endl;
    std::cout << "Периметр: " << triangle.perimeter() << std::endl;

    std::cout << "\nРазмер структуры Shape: " << sizeof(Shape) << " байт" << std::endl;

    return 0;
}"

#include <iostream>
#include <cstring>
using namespace std;

union ConfigValue {
    int int_val;
    double double_val;
    bool bool_val;
    char str_val[32];
};

struct ConfigEntry {
    enum ValueType { INT, DOUBLE, BOOL, STRING } type;
    char key[32];
    ConfigValue value;

    void serialize(char* buffer) const {
        char* ptr = buffer;

        strcpy(ptr, key);
        ptr += strlen(key) + 1;

        *reinterpret_cast<int*>(ptr) = type;
        ptr += sizeof(int);

        switch (type) {
            case INT:
                *reinterpret_cast<int*>(ptr) = value.int_val;
                ptr += sizeof(int);
                break;
            case DOUBLE:
                *reinterpret_cast<double*>(ptr) = value.double_val;
                ptr += sizeof(double);
                break;
            case BOOL:
                *ptr = value.bool_val ? 1 : 0;
                ptr += 1;
                break;
            case STRING:
                strcpy(ptr, value.str_val);
                ptr += strlen(value.str_val) + 1;
                break;
        }
    }

    void print() const {
        cout << key << \ = ";
        switch (type) {
            case INT: cout << value.int_val; break;
            case DOUBLE: cout << value.double_val; break;
            case BOOL: cout << (value.bool_val ? "true" : "false"); break;
            case STRING: cout << '"' << value.str_val << '"'; break;
        }
        cout << endl;
    }
};

int main() {
    ConfigEntry entries[3];

    strcpy(entries[0].key

keywords:
 "debug_mode");
    entries[2].type = ConfigEntry::BOOL;
    entries[2].value.bool_val = true;

    cout << "Конфигурация:" << endl;
    for (int i = 0; i < 3; i++) {
        entries[i].print();
    }

    char buffer[256];
    entries[0].serialize(buffer);

    cout << "\nРазмер ConfigEntry: " << sizeof(ConfigEntry) << " байт" << endl;
    cout << "Размер ConfigValue: " << sizeof(ConfigValue) << " байт" << endl;

    return 0;
}"

