#include <iostream>
#include <cmath>
using namespace std;

union Temperature {
    struct {
        double kelvin;
    } absolute;

    struct {
        double celsius;
    } metric;

    struct {
        double fahrenheit;
    } imperial;

    Temperature(double value = 0, int unit = 0) {
        switch (unit) {
            case 0:
                absolute.kelvin = value;
                convert_from_kelvin();
                break;
            case 1:
                metric.celsius = value;
                convert_from_celsius();
                break;
            case 2:
                imperial.fahrenheit = value;
                convert_from_fahrenheit();
                break;
        }
    }

    void convert_from_kelvin() {
        metric.celsius = absolute.kelvin - 273.15;
        imperial.fahrenheit = (absolute.kelvin - 273.15) * 9.0/5.0 + 32.0;
    }

    void convert_from_celsius() {
        absolute.kelvin = metric.celsius + 273.15;
        imperial.fahrenheit = metric.celsius * 9.0/5.0 + 32.0;
    }

    void convert_from_fahrenheit() {
        metric.celsius = (imperial.fahrenheit - 32.0) * 5.0/9.0;
        absolute.kelvin = metric.celsius + 273.15;
    }

    void set_kelvin(double k) {
        absolute.kelvin = k;
        convert_from_kelvin();
    }

    void set_celsius(double c) {
        metric.celsius = c;
        convert_from_celsius();
    }

    void set_fahrenheit(double f) {
        imperial.fahrenheit = f;
        convert_from_fahrenheit();
    }

    void print() const {
        cout << \Температура:" << endl;
        cout << "  Кельвин: " << absolute.kelvin << " K" << endl;
        cout << "  Цельсий: " << metric.celsius << " °C" << endl;
        cout << "  Фаренгейт: " << imperial.fahrenheit << " °F" << endl;
    }

    bool is_below_freezing() const {
        return metric.celsius < 0.0;
    }

    bool is_above_boiling() const {
        return metric.celsius > 100.0;
    }
};

int main() {
    Temperature t1(293.15

topic:
 2);
    Temperature t3;
    t3.set_celsius(100);

    cout << "Физические величины с разными единицами измерения:" << endl;
    cout << "=================================================" << endl;

    cout << "\nt1 (20°C в Кельвинах):" << endl;
    t1.print();
    cout << "Замерзает? " << (t1.is_below_freezing() ? "Да" : "Нет") << endl;

    cout << "\nt2 (20°C в Фаренгейтах):" << endl;
    t2.print();

    cout << "\nt3 (Точка кипения воды):" << endl;
    t3.print();
    cout << "Кипит? " << (t3.is_above_boiling() ? "Да" : "Нет") << endl;

    cout << "\nДемонстрация конверсии:" << endl;
    Temperature test;
    test.set_fahrenheit(212);
    test.print();

    cout << "\nРазмер Temperature: " << sizeof(Temperature) << " байт" << endl;

    return 0;
}"

