code:
#include <iostream>
#include <cmath>
#include <cstring>
#include <cstdio>
#include <cstdint>
using namespace std;

union AudioSample {
    short int16;
    unsigned short uint16;
    int int32;
    float float32;
    signed char int8;
    unsigned char uint8;
    unsigned char bytes[4];

    AudioSample() : int32(0) {}

    void from_float(float value) {
        float32 = value;
        normalize_to_int16();
        normalize_to_int8();
    }

    void normalize_to_int16() {
        if (float32 >= 1.0f) int16 = 32767;
        else if (float32 <= -1.0f) int16 = -32768;
        else int16 = static_cast<short>(float32 * 32767.0f);
    }

    void normalize_to_int8() {
        if (float32 >= 1.0f) int8 = 127;
        else if (float32 <= -1.0f) int8 = -128;
        else int8 = static_cast<signed char>(float32 * 127.0f);
    }

    void to_uint16() {
        uint16 = static_cast<unsigned short>(int16 + 32768);
    }

    void to_uint8() {
        uint8 = static_cast<unsigned char>(int8 + 128);
    }

    void print_formats() const {
        cout << \Аудио семпл в разных форматах:" << endl;
        cout << "  Float32: " << float32 << endl;
        cout << "  Int32: " << int32 << endl;
        cout << "  Int16: " << int16 << endl;
        cout << "  UInt16: " << uint16 << endl;
        cout << "  Int8: " << (int)int8 << endl;
        cout << "  UInt8: " << (int)uint8 << endl;
        cout << "  Байты: ";
        for (int i = 0; i < 4; i++) {
            printf("%02X "

style:
bytes[i]);
       }
       cout << endl;
   }

   static AudioSample generate_sine(float frequency

keywords:
 float sample_rate = 44100.0f) {
        AudioSample sample;
        float value = sin(2.0f * M_PI * frequency * time / sample_rate);
        sample.from_float(value);
        return sample;
    }

    static AudioSample generate_silence() {
        AudioSample sample;
        sample.from_float(0.0f);
        return sample;
    }
};

int main() {
    cout << "Аудио семплы в разных форматах:" << endl;
    cout << "================================" << endl;

    AudioSample silence = AudioSample::generate_silence();
    AudioSample sine_wave = AudioSample::generate_sine(440.0f

column6:
 0.0f);
    AudioSample half_amplitude;
    half_amplitude.from_float(0.5f);

    cout << "\n1. Тишина (0.0):" << endl;
    silence.print_formats();

    cout << "\n2. Синус 440 Гц:" << endl;
    sine_wave.print_formats();

    cout << "\n3. Половина амплитуды (0.5):" << endl;
    half_amplitude.print_formats();

    cout << "\nДемонстрация конверсии:" << endl;
    AudioSample test;
    test.from_float(0.75f);
    test.print_formats();

    cout << "\nПосле конверсии в unsigned:" << endl;
    test.to_uint16();
    test.to_uint8();
    test.print_formats();

    cout << "\nРазмер AudioSample: " << sizeof(AudioSample) << " байт" << endl;

    return 0;
}"

