#include <iostream>
#include <stdexcept>
using namespace std;

union StackValue {
    int int_val;
    double double_val;
    char char_val;
    bool bool_val;
};

enum ValueType { INT_TYPE, DOUBLE_TYPE, CHAR_TYPE, BOOL_TYPE };

struct TypedStack {
    static const int MAX_SIZE = 10;
    StackValue data[MAX_SIZE];
    ValueType types[MAX_SIZE];
    int top;

    TypedStack() : top(-1) {}

    void push(int value) {
        if (top >= MAX_SIZE - 1) throw runtime_error(\Stack overflow");
        top++;
        data[top].int_val = value;
        types[top] = INT_TYPE;
    }

    void push(double value) {
        if (top >= MAX_SIZE - 1) throw runtime_error("Stack overflow");
        top++;
        data[top].double_val = value;
        types[top] = DOUBLE_TYPE;
    }

    void push(char value) {
        if (top >= MAX_SIZE - 1) throw runtime_error("Stack overflow");
        top++;
        data[top].char_val = value;
        types[top] = CHAR_TYPE;
    }

    void push(bool value) {
        if (top >= MAX_SIZE - 1) throw runtime_error("Stack overflow");
        top++;
        data[top].bool_val = value;
        types[top] = BOOL_TYPE;
    }

    StackValue pop() {
        if (top < 0) throw runtime_error("Stack underflow");
        return data[top--];
    }

    ValueType top_type() const {
        if (top < 0) throw runtime_error("Stack is empty");
        return types[top];
    }

    void print() const {
        cout << "Стек (сверху вниз):" << endl;
        for (int i = top; i >= 0; i--) {
            cout << "  [" << i << "]: ";
            switch (types[i]) {
                case INT_TYPE: cout << "int: " << data[i].int_val; break;
                case DOUBLE_TYPE: cout << "double: " << data[i].double_val; break;
                case CHAR_TYPE: cout << "char: '" << data[i].char_val << "'"; break;
                case BOOL_TYPE: cout << "bool: " << (data[i].bool_val ? "true" : "false"); break;
            }
            cout << endl;
        }
        if (top < 0) cout << "  <пусто>" << endl;
    }
};

int main() {
    TypedStack stack;

    cout << "Демонстрация стека с разными типами:" << endl;

    stack.push(42);
    stack.push(3.14);
    stack.push('A');
    stack.push(true);
    stack.push(100);

    stack.print();

    cout << "\nТип верхнего элемента: ";
    switch (stack.top_type()) {
        case INT_TYPE: cout << "int"; break;
        case DOUBLE_TYPE: cout << "double"; break;
        case CHAR_TYPE: cout << "char"; break;
        case BOOL_TYPE: cout << "bool"; break;
    }
    cout << endl;

    cout << "\nИзвлекаем элементы:" << endl;
    while (true) {
        try {
            StackValue val = stack.pop();
            // Для демонстрации просто извлекаем

style:
 не используем значение
        } catch (const runtime_error& e) {
            cout << "Стек опустошен" << endl;
            break;
        }
    }

    stack.print();

    cout << "\nРазмер StackValue: " << sizeof(StackValue) << " байт" << endl;
    cout << "Экономия памяти по сравнению с отдельными массивами: " 
         << (4 * 10 * sizeof(int) - 10 * sizeof(StackValue)) << " байт" << endl;

    return 0;
}"

