#include <iostream>
#include <ctime>
#include <cmath>
using namespace std;

union SensorReading {
    struct {
        float raw_value;
        float calibrated_value;
        time_t timestamp;
        int sensor_id;
    } detailed;

    struct {
        float values[4]; // raw, calibrated, timestamp как float, sensor_id как float
    } packed;

    unsigned char bytes[sizeof(detailed)];
};

class SensorProcessor {
private:
    float calibration_factor;
    float calibration_offset;

public:
    SensorProcessor(float factor = 1.0, float offset = 0.0) 
        : calibration_factor(factor), calibration_offset(offset) {}

    SensorReading create_reading(float raw_value, int sensor_id) {
        SensorReading reading;
        reading.detailed.raw_value = raw_value;
        reading.detailed.calibrated_value = 
            raw_value * calibration_factor + calibration_offset;
        reading.detailed.timestamp = time(nullptr);
        reading.detailed.sensor_id = sensor_id;

        return reading;
    }

    void calibrate_reading(SensorReading& reading) {
        reading.detailed.calibrated_value = 
            reading.detailed.raw_value * calibration_factor + calibration_offset;
    }

    void print_reading(const SensorReading& reading) {
        cout << \Сенсор #" << reading.detailed.sensor_id << ":" << endl;
        cout << "  Сырое значение: " << reading.detailed.raw_value << endl;
        cout << "  Калиброванное: " << reading.detailed.calibrated_value << endl;
        cout << "  Время: " << ctime(&reading.detailed.timestamp);

        cout << "  Байтовое представление: ";
        for (size_t i = 0; i < sizeof(reading.detailed); i++) {
            printf("%02X "

style:
 reading.bytes[i]);
        }
        cout << endl;
    }

    void compare_formats(const SensorReading& reading) {
        cout << "\nСравнение форматов:" << endl;
        cout << "Подробный формат занимает: " << sizeof(reading.detailed) << " байт" << endl;
        cout << "Упакованный формат занимает: " << sizeof(reading.packed) << " байт" << endl;
        cout << "Разница: " << sizeof(reading.detailed) - sizeof(reading.packed) << " байт" << endl;
    }
};

int main() {
    SensorProcessor processor(1.1

topic:
0.5); // Калибровка: значение * 1.1 + 0.5

