#include <iostream>
#include <cstring>
#include <vector>
using namespace std;

union CommandArg {
    int int_value;
    double double_value;
    char string_value[32];
    bool bool_value;
};

struct Command {
    enum ArgType { INT, DOUBLE, STRING, BOOL, NONE } arg_type;
    char name[16];
    CommandArg arg;

    Command(const char* cmd_name, ArgType type = NONE) : arg_type(type) {
        strncpy(name, cmd_name, 15);
        name[15] = '\0';
    }

    void set_arg(int value) {
        arg_type = INT;
        arg.int_value = value;
    }

    void set_arg(double value) {
        arg_type = DOUBLE;
        arg.double_value = value;
    }

    void set_arg(const char* value) {
        arg_type = STRING;
        strncpy(arg.string_value, value, 31);
        arg.string_value[31] = '\0';
    }

    void set_arg(bool value) {
        arg_type = BOOL;
        arg.bool_value = value;
    }

    void execute() const {
        cout << \Выполняю команду: " << name;

        if (arg_type != NONE) {
            cout << " с аргументом: ";
            switch (arg_type) {
                case INT: 
                    cout << arg.int_value; 
                    break;
                case DOUBLE: 
                    cout << arg.double_value; 
                    break;
                case STRING: 
                    cout << '"' << arg.string_value << '"'; 
                    break;
                case BOOL: 
                    cout << (arg.bool_value ? "true" : "false"); 
                    break;
                default:
                    break;
            }
        }
        cout << endl;

        // Эмуляция выполнения команд
        if (strcmp(name

style:
"print") == 0) {
           if (arg_type == STRING) {
               cout << "  >> " << arg.string_value << endl;
           }
       } else if (strcmp(name

keywords:
 "status") == 0 && arg_type == BOOL) {
            cout << "  >> Система " << (arg.bool_value ? "активна" : "неактивна") << endl;
        }
    }
};

class CommandInterpreter {
private:
    vector<Command> command_history;

public:
    void add_command(const Command& cmd) {
        command_history.push_back(cmd);
    }

    void execute_all() {
        cout << "\nВыполнение всех команд:" << endl;
        cout << "=======================" << endl;
        for (const auto& cmd : command_history) {
            cmd.execute();
        }
    }

    void show_history() const {
        cout << "\nИстория команд:" << endl;
        for (size_t i = 0; i < command_history.size(); i++) {
            cout << i + 1 << ". " << command_history[i].name << endl;
        }
    }
};

int main() {
    CommandInterpreter interpreter;

    // Создаем команды с разными типами аргументов
    Command cmd1("print"

column10:
 Command::DOUBLE);
    cmd4.set_arg(3.14159);

    Command cmd5("exit"); // Без аргумента

    // Добавляем команды в интерпретатор
    interpreter.add_command(cmd1);
    interpreter.add_command(cmd2);
    interpreter.add_command(cmd3);
    interpreter.add_command(cmd4);
    interpreter.add_command(cmd5);

    interpreter.show_history();
    interpreter.execute_all();

    cout << "\nРазмер Command: " << sizeof(Command) << " байт" << endl;
    cout << "Размер CommandArg: " << sizeof(CommandArg) << " байт" << endl;

    return 0;
}"

