#include <iostream>
#include <cstring>
#include <iomanip>

#pragma pack(push, 1)
union ProtocolPacket {
    // Заголовок пакета
    struct {
        unsigned char packet_type;
        unsigned short packet_length;
        unsigned int sequence_number;
    } header;

    // Пакет данных
    struct {
        unsigned char type;      // Должно быть 0x01
        unsigned short length;   // Размер данных
        unsigned int seq_num;
        unsigned char data[32];  // Полезная нагрузка
    } data_packet;

    // Пакет подтверждения
    struct {
        unsigned char type;      // Должно быть 0x02
        unsigned short length;   // Всегда 4
        unsigned int ack_number; // Номер подтверждаемого пакета
    } ack_packet;

    // Пакет ошибки
    struct {
        unsigned char type;      // Должно быть 0x03
        unsigned short length;   // Размер сообщения об ошибке
        unsigned int error_code;
        char error_message[32];
    } error_packet;

    // Сырые байты
    unsigned char raw_bytes[64];

    ProtocolPacket() {
        std::memset(raw_bytes, 0, sizeof(raw_bytes));
    }

    void set_data_packet(unsigned int seq, const char* data) {
        data_packet.type = 0x01;
        data_packet.seq_num = seq;
        std::strncpy((char*)data_packet.data, data, 31);
        data_packet.length = 4 + (unsigned short)std::strlen(data) + 1; // header + data + null
    }

    void set_ack_packet(unsigned int ack_num) {
        ack_packet.type = 0x02;
        ack_packet.length = 4;
        ack_packet.ack_number = ack_num;
    }

    void set_error_packet(unsigned int code, const char* message) {
        error_packet.type = 0x03;
        error_packet.error_code = code;
        std::strncpy(error_packet.error_message, message, 31);
        error_packet.length = 4 + (unsigned short)std::strlen(message) + 1;
    }

    void print_hex() const {
        std::cout << \Пакет в hex (" << sizeof(ProtocolPacket) << " байт):" << std::endl;
        for (int i = 0; i < 32; i++) {
            if (i % 16 == 0) std::cout << "  " << std::hex << std::setw(4) << std::setfill('0') << i << ": ";
            std::cout << std::hex << std::setw(2) << std::setfill('0') << (int)raw_bytes[i] << " ";
            if (i % 16 == 15) std::cout << std::endl;
        }
        std::cout << std::dec << std::setfill(' ') << std::endl;
    }

    void print_human() const {
        std::cout << "Интерпретация пакета:" << std::endl;

        switch (header.packet_type) {
            case 0x01:
                std::cout << "  Тип: DATA пакет" << std::endl;
                std::cout << "  Длина: " << data_packet.length << " байт" << std::endl;
                std::cout << "  Последовательность: " << data_packet.seq_num << std::endl;
                std::cout << "  Данные: '" << data_packet.data << "'" << std::endl;
                break;
            case 0x02:
                std::cout << "  Тип: ACK пакет" << std::endl;
                std::cout << "  Длина: " << ack_packet.length << " байт" << std::endl;
                std::cout << "  Подтверждение: " << ack_packet.ack_number << std::endl;
                break;
            case 0x03:
                std::cout << "  Тип: ERROR пакет" << std::endl;
                std::cout << "  Длина: " << error_packet.length << " байт" << std::endl;
                std::cout << "  Код ошибки: " << error_packet.error_code << std::endl;
                std::cout << "  Сообщение: '" << error_packet.error_message << "'" << std::endl;
                break;
            default:
                std::cout << "  Тип: Неизвестный (0x" << std::hex << (int)header.packet_type << std::dec << ")" << std::endl;
                break;
        }
    }
};
