    cout << "\n3. Матрица инцидентности:" << endl;
    graph.print_incidence();

    // Статистика
    cout << "\nСтатистика:" << endl;
    cout << "Размер GraphRepresentation: " << sizeof(GraphRepresentation) << " байт" << endl;

    // Демонстрация доступа к данным
    cout << "\nДемонстрация доступа к данным:" << endl;
