class EventLogger {
private:
    std::vector<Event> events;

public:
    void log_event(const Event& event) {
        events.push_back(event);
    }

    void print_all() const {
        std::cout << "\nЛог событий (" << events.size() << " событий):" << std::endl;
        std::cout << "========================================" << std::endl;
        for (const auto& event : events) {
            event.print();
        }
    }

    void print_by_type(Event::EventType type) const {
        const char* type_names[] = {"Клавиатура"

column9:
 "Датчик"};
        std::cout << "\nСобытия типа '" << type_names[type] << "':" << std::endl;

        int count = 0;
        for (const auto& event : events) {
            if (event.type == type) {
                event.print();
                count++;
            }
        }
        std::cout << "Всего: " << count << " событий" << std::endl;
    }

    void clear() {
        events.clear();
    }
};

