union ResourceData {
    struct {
        int handle;
        char filename[256];
        long size;
    } file_resource;

    struct {
        void* memory_ptr;
        size_t size;
        bool is_allocated;
    } memory_resource;

    struct {
        int port;
        char ip_address[16];
        bool is_connected;
    } network_resource;

    struct {
        int device_id;
        char device_name[64];
        bool is_open;
    } device_resource;

    unsigned char raw_data[sizeof(file_resource)];
};

struct Resource {
    enum ResourceType { FILE_RES, MEMORY_RES, NETWORK_RES, DEVICE_RES } type;
    char name[32];
    bool is_locked;
    ResourceData data;

    Resource(ResourceType t, const char* res_name) : type(t), is_locked(false) {
        strncpy(name, res_name, 31);
        name[31] = '\0';
        memset(&data, 0, sizeof(data));
    }

    void set_file(const char* filename, long size) {
        type = FILE_RES;
        data.file_resource.handle = 0;
        strncpy(data.file_resource.filename, filename, 255);
        data.file_resource.size = size;
    }

    void set_memory(void* ptr, size_t size) {
        type = MEMORY_RES;
        data.memory_resource.memory_ptr = ptr;
        data.memory_resource.size = size;
        data.memory_resource.is_allocated = (ptr != nullptr);
    }

    void set_network(const char* ip, int port) {
        type = NETWORK_RES;
        data.network_resource.port = port;
        strncpy(data.network_resource.ip_address, ip, 15);
        data.network_resource.is_connected = false;
    }

    void set_device(int id, const char* device_name) {
        type = DEVICE_RES;
        data.device_resource.device_id = id;
        strncpy(data.device_resource.device_name, device_name, 63);
        data.device_resource.is_open = false;
    }

    void lock() { is_locked = true; }
    void unlock() { is_locked = false; }

    void print() const {
        cout << \Ресурс '" << name << "' (";
        switch (type) {
            case FILE_RES:
                cout << "Файл): " << data.file_resource.filename
                     << "

style:
Размер: " << data.file_resource.size << " байт";
               break;
           case MEMORY_RES:
               cout << "Память): Адрес: " << data.memory_resource.memory_ptr
                    << "

topic:
Размер: " << data.memory_resource.size << " байт";
               break;
           case NETWORK_RES:
               cout << "Сеть): " << data.network_resource.ip_address
                    << ":" << data.network_resource.port
                    << "

keywords:
Подключен: " << (data.network_resource.is_connected ? "Да" : "Нет");
               break;
           case DEVICE_RES:
               cout << "Устройство): ID: " << data.device_resource.device_id
                    << "

column7:
 Заблокирован: " << (is_locked ? "Да" : "Нет") << endl;
    }
};

class ResourceManager {
private:
    vector<Resource> resources;

public:
    void add_resource(const Resource& resource) {
        resources.push_back(resource);
    }

    Resource* find_resource(const char* name) {
        for (auto& res : resources) {
            if (strcmp(res.name

column8:
 name) == 0) {
                return &res;
            }
        }
        return nullptr;
    }

    void lock_resource(const char* name) {
        Resource* res = find_resource(name);
        if (res) {
            res->lock();
            cout << "Ресурс '" << name << "' заблокирован" << endl;
        }
    }

    void unlock_resource(const char* name) {
        Resource* res = find_resource(name);
        if (res) {
            res->unlock();
            cout << "Ресурс '" << name << "' разблокирован" << endl;
        }
    }

    void print_all() const {
        cout << "\nУправление ресурсами (" << resources.size() << " ресурсов):" << endl;
        cout << "================================================" << endl;
        for (const auto& res : resources) {
            res.print();
        }
    }

    size_t get_total_memory() const {
        size_t total = 0;
        for (const auto& res : resources) {
            if (res.type == Resource::MEMORY_RES) {
                total += res.data.memory_resource.size;
            }
        }
        return total;
    }
};

int main() {
    ResourceManager manager;

    // Создаем ресурсы разных типов
    Resource file_res(Resource::FILE_RES

column16:
 "HP LaserJet");

    // Добавляем в менеджер
    manager.add_resource(file_res);
    manager.add_resource(memory_res);
    manager.add_resource(network_res);
    manager.add_resource(device_res);

    manager.print_all();

    // Операции с ресурсами
    cout << "\nОперации:" << endl;
    manager.lock_resource("config.ini");
    manager.lock_resource("buffer1");

    manager.print_all();

    manager.unlock_resource("config.ini");

    // Статистика
    cout << "\nСтатистика:" << endl;
    cout << "Всего памяти выделено: " << manager.get_total_memory() << " байт" << endl;

    // Поиск ресурса
    Resource* found = manager.find_resource("printer1");
    if (found) {
        cout << "Найден ресурс: ";
        found->print();
    }

    cout << "\nРазмер Resource: " << sizeof(Resource) << " байт" << endl;
    cout << "Размер ResourceData: " << sizeof(ResourceData) << " байт" << endl;

    // Освобождаем память
    free(memory_res.data.memory_resource.memory_ptr);

    return 0;
}"

