 LogLevel levels[] = {LogLevel::DEBUG

topic:
 LogLevel::ERROR};

 for (LogLevel level : levels) {
 cout << "Уровень лога " << static_cast<int>(level) 
 << ": " << logLevelToString(level) << endl;
 }

 return 0;
}"

