#include <iostream>
using namespace std;

enum Direction { NORTH = 0, EAST = 90, SOUTH = 180, WEST = 270, NORTHEAST = 45 };

bool isValidDirection(int degrees) {
 return (degrees == NORTH || degrees == EAST || degrees == SOUTH || 
 degrees == WEST || degrees == NORTHEAST);
}

int main() {
 Direction dir = SOUTH;
 cout << \Текущее направление: " << dir << " градусов" << endl;

 cout << "Проверка 90 градусов: " << (isValidDirection(90) ? "валидно" : "не валидно") << endl;
 cout << "Проверка 45 градусов: " << (isValidDirection(NORTHEAST) ? "валидно" : "не валидно") << endl;
 cout << "Проверка 100 градусов: " << (isValidDirection(100) ? "валидно" : "не валидно") << endl;

 return 0;
}"

