#include <iostream>
#include <string>
using namespace std;

class StringQueue {
    string data[50];
    int front, rear;
public:
    StringQueue() : front(0), rear(0) {}
    void enqueue(string s) { data[rear++] = s; }
    string dequeue() { return data[front++]; }
    bool isEmpty() const { return front == rear; }
};

int main() {
    StringQueue queue;
    queue.enqueue(\Первый");
    queue.enqueue("Второй");
    queue.enqueue("Третий");

    cout << "Извлечение из очереди:" << endl;
    while (!queue.isEmpty()) {
        cout << queue.dequeue() << endl;
    }
    return 0;
}"

