#include <iostream>
using namespace std;

class IntStack {
    int data[100];
    int top;
public:
    IntStack() : top(-1) {}
    void push(int value) { data[++top] = value; }
    int pop() { return data[top--]; }
    bool isEmpty() const { return top == -1; }
};

int main() {
    IntStack stack;
    stack.push(10);
    stack.push(20);
    stack.push(30);

    cout << \Извлечение из стека:" << endl;
    while (!stack.isEmpty()) {
        cout << stack.pop() << endl;
    }
    return 0;
}"

