class Cache {
    mutable std::string cachedValue;
    mutable bool isValid;
    std::string computeValue() const {
        return \Computed at: " + std::to_string(std::time(nullptr));
    }
public:
    Cache() : isValid(false) {}
    std::string getValue() const {
        if(!isValid) {
            cachedValue = computeValue();
            isValid = true;
            std::cout << "Value computed and cached" << std::endl;
        }
        return cachedValue;
