    void next() {
        switch(currentState) {
            case State::RED: currentState = State::GREEN; break;
            case State::GREEN: currentState = State::YELLOW; break;
            case State::YELLOW: currentState = State::RED; break;
        }
    }
    std::string getState() const {
        switch(currentState) {
            case State::RED: return \RED";
            case State::GREEN: return "GREEN";
            case State::YELLOW: return "YELLOW";
            default: return "UNKNOWN";
        }
    }
};

int main() {
    TrafficLight light;
    for(int i = 0; i < 5; i++) {
        std::cout << "Light is: " << light.getState() << std::endl;
        light.next();
    }
    return 0;
}"

#include <iostream>
using namespace std;

class Packet {
public:
    unsigned int version : 4;
    unsigned int headerLength : 4;
    unsigned int type : 2;
    unsigned int priority : 3;
    unsigned int reserved : 1;
    Packet() : version(1), headerLength(5), type(0), priority(0), reserved(0) {}
    void display() const {
        cout << \Version: " << version << endl;
        cout << "Header Length: " << headerLength << endl;
        cout << "Type: " << type << endl;
        cout << "Priority: " << priority << endl;
        cout << "Reserved: " << reserved << endl;
        cout << "Total bits: " << (4+4+2+3+1) << endl;
    }
};

int main() {
    Packet pkt;
    pkt.display();
    pkt.version = 2;
    pkt.priority = 5;
    cout << "\nAfter modification:" << endl;
    pkt.display();
    return 0;
}"

