#include <iostream>
using namespace std;

class Circle {
    double radius;
    mutable double cachedArea;
    mutable bool areaValid;
public:
    Circle(double r) : radius(r), cachedArea(0), areaValid(false) {}
    void setRadius(double r) {
        radius = r;
        areaValid = false;
    }
    double getArea() const {
        if(!areaValid) {
            cachedArea = 3.14159 * radius * radius;
            areaValid = true;
            cout << \Area calculated and cached" << endl;
        }
        return cachedArea;
    }
};

int main() {
    const Circle circle(5.0);
    cout << "Area: " << circle.getArea() << endl;
    cout << "Area: " << circle.getArea() << endl;
    return 0;
}"

