    Indicator() : active(false) {}
    void activate() { 
        active = true; 
        cout << \Indicator activated" << endl;
    }
    void deactivate() { 
        active = false; 
        cout << "Indicator deactivated" << endl;
    }
    bool isActive() const { 
        return active; 
    }
    void status() const {
        cout << "Indicator is " << (active ? "ON" : "OFF") << endl;
    }
};

