#include <iostream>
using namespace std;

class NonCopyable {
    int id;
public:
    explicit NonCopyable(int i) : id(i) {
        cout << \NonCopyable " << id << " created" << endl;
    }
    ~NonCopyable() {
        cout << "NonCopyable " << id << " destroyed" << endl;
    }
    // Запрещаем копирование
    NonCopyable(const NonCopyable&) = delete;
    NonCopyable& operator=(const NonCopyable&) = delete;
    // Разрешаем перемещение
    NonCopyable(NonCopyable&&) = default;
    NonCopyable& operator=(NonCopyable&&) = default;
    int getId() const { return id; }
};

int main() {
    NonCopyable nc1(1);
    // NonCopyable nc2 = nc1; // Ошибка: конструктор копирования удален
    NonCopyable nc3(2);
    // nc3 = nc1; // Ошибка: оператор присваивания удален
    NonCopyable nc4 = move(nc3); // OK: перемещение разрешено
    cout << "nc4 id: " << nc4.getId() << endl;
    return 0;
}"

