class LargeObject {
public:
    LargeObject(size_t size) : data(new int[size]), size(size) {
        cout << \Конструктор " << size << endl;
    }

    LargeObject(LargeObject&& other) noexcept 
        : data(other.data)

style:
 size(other.size) {
        other.data = nullptr;
        other.size = 0;
        cout << "Move конструктор" << endl;
    }

    LargeObject& operator=(LargeObject&& other) noexcept {
        if (this != &other) {
            delete[] data;
            data = other.data;
            size = other.size;
            other.data = nullptr;
            other.size = 0;
            cout << "Move оператор присваивания" << endl;
        }
        return *this;
    }

    ~LargeObject() {
        delete[] data;
        cout << "Деструктор" << endl;
    }

private:
