        other.size = 0;
        std::cout << "Move конструктор" << std::endl;
    }

    LargeObject& operator=(LargeObject&& other) noexcept {
        if (this != &other) {
            delete[] data;
            data = other.data;
            size = other.size;
            other.data = nullptr;
            other.size = 0;
            std::cout << "Move оператор присваивания" << std::endl;
        }
        return *this;
    }

    ~LargeObject() {
        delete[] data;
        std::cout << "Деструктор" << std::endl;
    }

private:
    int* data;
    std::size_t size;
};

int main() {
    LargeObject obj1(1000);
    LargeObject obj2 = std::move(obj1);

    std::vector<LargeObject> objects;
    objects.push_back(LargeObject(500));

    return 0;
}"

