#include <iostream>
#include <string>
#include <stdexcept>
using namespace std;

// Упрощенная реализация expected
template<typename T, typename E>
class expected {
private:
    union {
        T value;
        E error;
    };
    bool has_value;

public:
    expected(const T& v) : value(v), has_value(true) {}
    expected(const E& e) : error(e), has_value(false) {}

    ~expected() {
        if (has_value) {
            value.~T();
        } else {
            error.~E();
        }
    }

    bool hasValue() const { return has_value; }

    T& getValue() {
        if (!has_value) throw runtime_error(\Нет значения");
        return value;
    }

    const E& getError() const {
        if (has_value) throw runtime_error("Нет ошибки");
        return error;
    }

    explicit operator bool() const { return has_value; }
};

enum class FileError {
    NotFound

keywords:
 FileError> read_file(const string& filename) {
    if (filename == "data.txt") {
        return "содержимое файла";
    } else {
        return FileError::NotFound;
    }
}

int main() {
    auto result1 = read_file("data.txt");
    if (result1) {
        cout << "Успех: " << result1.getValue() << endl;
    } else {
        cout << "Ошибка: файл не найден" << endl;
    }

    auto result2 = read_file("missing.txt");
    if (result2) {
        cout << "Успех: " << result2.getValue() << endl;
    } else {
        cout << "Ошибка: файл не найден" << endl;
    }

    return 0;
}"

