#include <iostream>
#include <memory>
#include <string>
using namespace std;

class Any {
    struct Base {
        virtual ~Base() = default;
        virtual unique_ptr<Base> clone() = 0;
    };
    template<typename T>
    struct Derived : Base {
        T value;
        Derived(const T& v) : value(v) {}
        unique_ptr<Base> clone() override {
            return make_unique<Derived<T>>(value);
        }
    };
    unique_ptr<Base> ptr;
public:
    template<typename T>
    Any(const T& value) : ptr(make_unique<Derived<T>>(value)) {}
    Any(const Any& other) : ptr(other.ptr->clone()) {}
};

int main() {
    Any a1 = 42;
    Any a2 = string(\Hello");
    Any a3 = a1;
    return 0;
}"

#include <iostream>
#include <memory>
#include <string>

class Any {
    struct Base {
        virtual ~Base() = default;
        virtual std::unique_ptr<Base> clone() = 0;
    };
    template<typename T>
    struct Derived : Base {
        T value;
        Derived(const T& v) : value(v) {}
        std::unique_ptr<Base> clone() override {
            return std::make_unique<Derived<T>>(value);
        }
    };
    std::unique_ptr<Base> ptr;
public:
    template<typename T>
    Any(const T& value) : ptr(std::make_unique<Derived<T>>(value)) {}
    Any(const Any& other) : ptr(other.ptr->clone()) {}
};

int main() {
