 cout <<  1 == f2: " << (f1 == f2) << endl;
 cout << "f1 != f3: " << (f1 != f3) << endl;
 cout << "f1 < f3: " << (f1 < f3) << endl;
 cout << "f3 > f1: " << (f3 > f1) << endl;
 return 0;
}"

