#include <iostream>
using namespace std;

class SafePointer {
 int* ptr;
public:
 SafePointer(int* p = nullptr) : ptr(p) {}
 explicit operator bool() const {
 return ptr != nullptr;
 }
 int& operator*() {
 if(!ptr) throw runtime_error(\Dereferencing null pointer");
 return *ptr;
 }
};

int main() {
 int value = 42;
 SafePointer sp1(&value);
 SafePointer sp2(nullptr);
 if(sp1) {
 cout << "sp1 is valid: " << *sp1 << endl;
 }
 if(!sp2) {
 cout << "sp2 is null" << endl;
 }
 return 0;
}"

