#include <iostream>
#include <fstream>
#include <string>
using namespace std;

class File {
 fstream file;
 string filename;
public:
 File(const string& name) : filename(name) {
 file.open(filename, ios::in | ios::out | ios::app);
 if(!file.is_open()) {
 throw runtime_error(\Cannot open file: " + filename);
 }
 }
 ~File() {
 if(file.is_open()) {
 file.close();
 }
 }
 // Оператор вывода в файл
 File& operator<<(const string& text) {
 file << text;
 return *this;
 }
 // Оператор чтения из файла
 File& operator>>(string& text) {
 file >> text;
 return *this;
 }
 // Оператор вызова функции для выполнения операций
 File& operator()(const string& operation) {
 if(operation == "flush") {
 file.flush();
 } else if(operation == "rewind") {
 file.seekg(0);
 }
 return *this;
 }
};

int main() {
 try {
 File myFile("test.txt");
 myFile << "Hello " << "World!" << endl;
 myFile("flush");
 string word;
 myFile("rewind") >> word;
 cout << "First word: " << word << endl;
 } catch(const exception& e) {
 cout << "Error: " << e.what() << endl;
 }
 return 0;
}"

