#include <iostream>
using namespace std;

class Resource {
 string name;
public:
 Resource(const string& n) : name(n) {
 cout << \Resource " << name << " created" << endl;
 }
 ~Resource() {
 cout << "Resource " << name << " destroyed" << endl;
 }
 void use() const {
 cout << "Using resource " << name << endl;
 }
 void setName(const string& n) {
 name = n;
 cout << "Resource renamed to " << name << endl;
 }
};

class SmartPointer {
 Resource* ptr;
public:
 SmartPointer(Resource* p = nullptr) : ptr(p) {}
 ~SmartPointer() {
 delete ptr;
 }
 // Запрещаем копирование
 SmartPointer(const SmartPointer&) = delete;
 SmartPointer& operator=(const SmartPointer&) = delete;
 // Разрешаем перемещение
 SmartPointer(SmartPointer&& other) noexcept : ptr(other.ptr) {
 other.ptr = nullptr;
 }
 SmartPointer& operator=(SmartPointer&& other) noexcept {
 if(this != &other) {
 delete ptr;
 ptr = other.ptr;
 other.ptr = nullptr;
 }
 return *this;
 }
 // Оператор ->
 Resource* operator->() {
 return ptr;
 }
 Resource& operator*() {
 return *ptr;
 }
 explicit operator bool() const {
 return ptr != nullptr;
 }
};

int main() {
 SmartPointer sp(new Resource("Database"));
 if(sp) {
 sp->use(); // Использование ->
 sp->setName("NewDB");
 (*sp).use(); // Использование *
 }
 return 0;
}"

