 return Complex(real + other.real, imag + other.imag);
 }
 Complex operator-(const Complex& other) const {
 return Complex(real - other.real, imag - other.imag);
 }
 Complex operator*(const Complex& other) const {
 return Complex(real * other.real - imag * other.imag,
 real * other.imag + imag * other.real);
 }
 Complex operator/(const Complex& other) const {
 double denominator = other.real * other.real + other.imag * other.imag;
 return Complex((real * other.real + imag * other.imag) / denominator,
 (imag * other.real - real * other.imag) / denominator);
 }
 // Составные присваивания
 Complex& operator+=(const Complex& other) {
 real += other.real;
 imag += other.imag;
 return *this;
 }
 Complex& operator-=(const Complex& other) {
 real -= other.real;
 imag -= other.imag;
 return *this;
 }
 // Унарные операторы
 Complex operator+() const { return *this; }
 Complex operator-() const { return Complex(-real, -imag); }
 // Сравнение
 bool operator==(const Complex& other) const {
 return real == other.real && imag == other.imag;
 }
 bool operator!=(const Complex& other) const {
 return !(*this == other);
 }
 // Модуль и аргумент
 double magnitude() const { return std::sqrt(real * real + imag * imag); }
 double argument() const { return std::atan2(imag, real); }
 // Сопряженное
 Complex conjugate() const { return Complex(real, -imag); }
 friend std::ostream& operator<<(std::ostream& os, const Complex& c) {
 return os << c.real << (c.imag >= 0 ? \ + " : " - ") << std::abs(c.imag) << "i";
 }
};

