code:
#include <iostream>
using namespace std;

class Date {
 int day, month, year;
 bool isValidDate(int d, int m, int y) const {
 if(m < 1 || m > 12) return false;
 if(d < 1) return false;
 int daysInMonth[] = {31,28,31,30,31,30,31,31,30,31,30,31};
 if(m == 2 && isLeapYear(y)) daysInMonth[1] = 29;
 return d <= daysInMonth[m-1];
 }
 bool isLeapYear(int y) const {
 return (y % 4 == 0 && y % 100 != 0) || (y % 400 == 0);
 }
public:
 Date(int d = 1, int m = 1, int y = 2000) {
 if(isValidDate(d, m, y)) {
 day = d; month = m; year = y;
 } else {
 day = 1; month = 1; year = 2000;
 }
 }
 // Инкремент даты
 Date& operator++() {
 day++;
 int daysInMonth[] = {31,28,31,30,31,30,31,31,30,31,30,31};
 if(month == 2 && isLeapYear(year)) daysInMonth[1] = 29;
 if(day > daysInMonth[month-1]) {
 day = 1;
 month++;
 if(month > 12) {
 month = 1;
 year++;
 }
 }
 return *this;
 }
 Date operator++(int) {
 Date temp = *this;
 ++(*this);
 return temp;
 }
 // Сложение с количеством дней
 Date operator+(int days) const {
 Date result = *this;
 for(int i = 0; i < days; i++) {
 ++result;
 }
 return result;
 }
 friend Date operator+(int days, const Date& date) {
 return date + days;
 }
 // Разность дат
 int operator-(const Date& other) const {
 // Простая реализация - в реальном коде нужно учитывать все месяцы и годы
 return (year - other.year) * 365 + (month - other.month) * 30 + (day - other.day);
 }
 // Сравнение дат
 bool operator==(const Date& other) const {
 return day == other.day && month == other.month && year == other.year;
 }
 bool operator<(const Date& other) const {
 if(year != other.year) return year < other.year;
 if(month != other.month) return month < other.month;
 return day < other.day;
 }
 bool operator>(const Date& other) const {
 return other < *this;
 }
 bool operator<=(const Date& other) const {
 return !(other < *this);
 }
 bool operator>=(const Date& other) const {
 return !(*this < other);
 }
 friend ostream& operator<<(ostream& os, const Date& date) {
 return os << date.day << /" << date.month << "/" << date.year;
 }
};

