#include <iostream>
#include <numeric>
using namespace std;

class Fraction {
 int numerator, denominator;
 void simplify() {
 int gcdVal = gcd(numerator, denominator);
 numerator /= gcdVal;
 denominator /= gcdVal;
 if(denominator < 0) {
 numerator = -numerator;
 denominator = -denominator;
 }
 }
public:
 Fraction(int num = 0, int den = 1) : numerator(num), denominator(den) {
 if(denominator == 0) denominator = 1;
 simplify();
