 Fraction temp = *this;
 numerator += denominator;
 simplify();
 return temp;
 }
 // Сравнение
 bool operator==(const Fraction& other) const {
 return numerator == other.numerator && denominator == other.denominator;
 }
 bool operator!=(const Fraction& other) const {
 return !(*this == other);
 }
 bool operator<(const Fraction& other) const {
