#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    vector<double> numbers = {3.1, 2.5, 6.7, 1.8, 9.2, 4.4, 5.5};

    sort(numbers.begin(), numbers.end());

    double median;
    if (numbers.size() % 2 == 0) {
        median = (numbers[numbers.size()/2 - 1] + numbers[numbers.size()/2]) / 2.0;
    } else {
        median = numbers[numbers.size()/2];
    }

    cout << \Отсортированные числа: ";
    for (double num : numbers) {
        cout << num << " ";
    }
    cout << endl;
    cout << "Медиана: " << median << endl;

    return 0;
}"

