#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    vector<int> numbers = {2, 4, 6, 8, 10};

    bool allEven = all_of(numbers.begin(), numbers.end(),
                         [](int x) { return x % 2 == 0; });

    bool anyOdd = any_of(numbers.begin(), numbers.end(),
                        [](int x) { return x % 2 != 0; });

    bool noneNegative = none_of(numbers.begin(), numbers.end(),
                               [](int x) { return x < 0; });

    cout << \Все числа четные: " << boolalpha << allEven << endl;
    cout << "Есть нечетные: " << anyOdd << endl;
    cout << "Нет отрицательных: " << noneNegative << endl;

    return 0;
}"

