#include <iostream>
#include <chrono>
#include <thread>
using namespace std;
using namespace chrono;

void long_operation() {
    this_thread::sleep_for(milliseconds(500));
}

int main() {
    auto start = high_resolution_clock::now();

    long_operation();

    auto end = high_resolution_clock::now();
    auto duration = duration_cast<milliseconds>(end - start);

    cout << \Операция заняла: " << duration.count() << " мс" << endl;

    auto now = system_clock::now();
    time_t now_time = system_clock::to_time_t(now);
    cout << "Текущее время: " << ctime(&now_time);

    steady_clock::time_point steady_start = steady_clock::now();
    this_thread::sleep_for(milliseconds(100));
    steady_clock::time_point steady_end = steady_clock::now();

    auto steady_duration = duration_cast<microseconds>(steady_end - steady_start);
    cout << "Steady clock duration: " << steady_duration.count() << " мкс" << endl;

    return 0;
}"

#include <iostream>
#include <chrono>
#include <thread>
#include <ctime>

void long_operation() {
    std::this_thread::sleep_for(std::chrono::milliseconds(500));
}

int main() {
    auto start = std::chrono::high_resolution_clock::now();

    long_operation();

    auto end = std::chrono::high_resolution_clock::now();
    auto duration = std::chrono::duration_cast<std::chrono::milliseconds>(end - start);

    std::cout << \Операция заняла: " << duration.count() << " мс" << std::endl;

    auto now = std::chrono::system_clock::now();
    std::time_t now_time = std::chrono::system_clock::to_time_t(now);
    std::cout << "Текущее время: " << std::ctime(&now_time);

    std::chrono::steady_clock::time_point steady_start = std::chrono::steady_clock::now();
    std::this_thread::sleep_for(std::chrono::milliseconds(100));
    std::chrono::steady_clock::time_point steady_end = std::chrono::steady_clock::now();

    auto steady_duration = std::chrono::duration_cast<std::chrono::microseconds>(steady_end - steady_start);
    std::cout << "Steady clock duration: " << steady_duration.count() << " мкс" << std::endl;

    return 0;
}"

