#include <iostream>
using namespace std;

constexpr int factorial(int n) {
    return (n <= 1) ? 1 : n * factorial(n - 1);
}

constexpr int fibonacci(int n) {
    return (n <= 1) ? n : fibonacci(n - 1) + fibonacci(n - 2);
}

class Circle {
private:
    double radius;

public:
    constexpr Circle(double r) : radius(r) {}

    constexpr double area() const {
        return 3.14159 * radius * radius;
    }
};

int main() {
    constexpr int fact_5 = factorial(5);
    constexpr int fib_10 = fibonacci(10);
    constexpr Circle c(5.0);

    cout << \Факториал 5: " << fact_5 << endl;
    cout << "Фибоначчи 10: " << fib_10 << endl;
    cout << "Площадь круга: " << c.area() << endl;

    int arr[factorial(3)]; // Массив размером 6
    cout << "Размер массива: " << sizeof(arr)/sizeof(arr[0]) << endl;

    return 0;
}"

