#include <iostream>
#include <memory>
#include <functional>

class AnyCallable {
private:
    struct Concept {
        virtual ~Concept() = default;
        virtual void call() = 0;
    };

    template<typename T>
    struct Model : Concept {
        T callable;
        Model(T&& c) : callable(std::forward<T>(c)) {}
        void call() override { callable(); }
    };

    std::unique_ptr<Concept> pimpl;

public:
    template<typename T>
    AnyCallable(T&& callable) 
        : pimpl(std::make_unique<Model<T>>(std::forward<T>(callable))) {}

    void operator()() {
        pimpl->call();
    }
};

int main() {
    int counter = 0;

    AnyCallable f1([]() { std::cout << \Лямбда без захвата" << std::endl; });
    AnyCallable f2([&counter]() { 
        counter++;
        std::cout << "Лямбда с захватом

style:
 counter = " << counter << std::endl; 
    });

    f1();
    f2();
    f2();

    return 0;
}"

