#include <iostream>
#include <type_traits>
using namespace std;

template<typename T>
constexpr void print_type_info() {
    if constexpr (is_integral_v<T>) {
        if constexpr (is_signed_v<T>) {
            cout << \Знаковый целочисленный тип" << endl;
        } else {
            cout << "Беззнаковый целочисленный тип" << endl;
        }
    } else if constexpr (is_floating_point_v<T>) {
        cout << "Вещественный тип" << endl;
    } else if constexpr (is_pointer_v<T>) {
        cout << "Указатель" << endl;
    } else {
        cout << "Другой тип" << endl;
    }
}

template<size_t N>
constexpr size_t factorial() {
    if constexpr (N == 0) {
        return 1;
    } else {
        return N * factorial<N - 1>();
    }
}

int main() {
    print_type_info<int>();
    print_type_info<double>();
    print_type_info<int*>();
    print_type_info<string>();

    constexpr auto fact_5 = factorial<5>();
    cout << "Факториал 5: " << fact_5 << endl;

    return 0;
}"

#include <iostream>
#include <type_traits>
#include <string>

template<typename T>
constexpr void print_type_info() {
    if constexpr (std::is_integral_v<T>) {
        if constexpr (std::is_signed_v<T>) {
            std::cout << \Знаковый целочисленный тип" << std::endl;
        } else {
            std::cout << "Беззнаковый целочисленный тип" << std::endl;
        }
    } else if constexpr (std::is_floating_point_v<T>) {
        std::cout << "Вещественный тип" << std::endl;
    } else if constexpr (std::is_pointer_v<T>) {
        std::cout << "Указатель" << std::endl;
    } else {
        std::cout << "Другой тип" << std::endl;
    }
}

template<size_t N>
constexpr size_t factorial() {
    if constexpr (N == 0) {
        return 1;
    } else {
        return N * factorial<N - 1>();
    }
}

int main() {
    print_type_info<int>();
    print_type_info<double>();
    print_type_info<int*>();
    print_type_info<std::string>();

    constexpr auto fact_5 = factorial<5>();
    std::cout << "Факториал 5: " << fact_5 << std::endl;

    return 0;
}"

