#include <iostream>
#include <bit>
#include <cstdint>
using namespace std;

const char* endian_to_string(endian e) {
    switch (e) {
        case endian::little: return \little-endian";
        case endian::big: return "big-endian";
        case endian::native: return "native";
        default: return "mixed-endian";
    }
}

bool is_little_endian() {
    return endian::native == endian::little;
}

bool is_big_endian() {
    return endian::native == endian::big;
}

uint32_t swap_endian(uint32_t value) {
    return ((value & 0x000000FF) << 24) |
           ((value & 0x0000FF00) << 8) |
           ((value & 0x00FF0000) >> 8) |
           ((value & 0xFF000000) >> 24);
}

int main() {
    cout << "Порядок байтов системы: " << endian_to_string(endian::native) << endl;
    cout << "Little-endian: " << (is_little_endian() ? "да" : "нет") << endl;
    cout << "Big-endian: " << (is_big_endian() ? "да" : "нет") << endl;

    // Проверка на конкретном числе
    uint32_t test_value = 0x12345678;
    cout << "\nИсходное значение: 0x" << hex << test_value << dec << endl;

    if (is_little_endian()) {
        cout << "Система little-endian - порядок байтов обратный" << endl;
        uint32_t swapped = swap_endian(test_value);
        cout << "После смены endian: 0x" << hex << swapped << dec << endl;
    } else {
        cout << "Система big-endian - порядок байтов прямой" << endl;
    }

    // Проверка с помощью union
    union {
        uint32_t i;
        uint8_t c[4];
    } test_union;

    test_union.i = 0x01020304;
    cout << "\nПроверка через union:" << endl;
    cout << "Байты: ";
    for (int i = 0; i < 4; ++i) {
        cout << "0x" << hex << (int)test_union.c[i] << " ";
    }
    cout << dec << endl;

    return 0;
}"

#include <iostream>
#include <bit>
#include <cstdint>

const char* endian_to_string(std::endian e) {
    switch (e) {
        case std::endian::little: return \little-endian";
        case std::endian::big: return "big-endian";
        case std::endian::native: return "native";
        default: return "mixed-endian";
    }
}

bool is_little_endian() {
    return std::endian::native == std::endian::little;
}

bool is_big_endian() {
    return std::endian::native == std::endian::big;
}

uint32_t swap_endian(uint32_t value) {
    return ((value & 0x000000FF) << 24) |
           ((value & 0x0000FF00) << 8) |
           ((value & 0x00FF0000) >> 8) |
           ((value & 0xFF000000) >> 24);
}

int main() {
    std::cout << "Порядок байтов системы: " << endian_to_string(std::endian::native) << std::endl;
    std::cout << "Little-endian: " << (is_little_endian() ? "да" : "нет") << std::endl;
    std::cout << "Big-endian: " << (is_big_endian() ? "да" : "нет") << std::endl;

    // Проверка на конкретном числе
    uint32_t test_value = 0x12345678;
    std::cout << "\nИсходное значение: 0x" << std::hex << test_value << std::dec << std::endl;

    if (is_little_endian()) {
        std::cout << "Система little-endian - порядок байтов обратный" << std::endl;
        uint32_t swapped = swap_endian(test_value);
        std::cout << "После смены endian: 0x" << std::hex << swapped << std::dec << std::endl;
    } else {
        std::cout << "Система big-endian - порядок байтов прямой" << std::endl;
    }

