        std::cout << "Указатель на: " << *value << std::endl;
    } else {
        std::cout << "Другой тип: " << value << std::endl;
    }
}

template<typename T>
class Container {
    static_assert(!std::is_pointer_v<T>

style:
 "Указатели не поддерживаются");
public:
    void add(const T& item) {
        std::cout << "Добавлен: " << item << std::endl;
    }
};

