// SFINAE для типов с методом serialize()
template<typename T>
class has_serialize {
private:
    template<typename U>
    static auto test(int) -> decltype(
        std::declval<U>().serialize(), std::true_type{});

    template<typename U>
    static std::false_type test(...);

public:
    static constexpr bool value = decltype(test<T>(0))::value;
};

template<typename T>
