serialize(const T& obj) {
    return std::to_string(obj);
}

class MyClass {
public:
    std::string serialize() const {
        return \MyClass serialized";
    }
};

int main() {
    MyClass obj;
    int number = 42;

    std::cout << serialize(obj) << std::endl;
    std::cout << serialize(number) << std::endl;

    return 0;
}"

