style:
 size_t len) {
    unsigned long long result = 0;
    for (size_t i = 0; i < len; i++) {
        result <<= 1;
        if (str[i] == '1') {
            result |= 1;
        }
    }
    return result;
}

// Литералы для пользовательских типов
class Temperature {
private:
    double kelvin;

public:
    constexpr Temperature(double k) : kelvin(k) {}

    double toCelsius() const { return kelvin - 273.15; }
    double toFahrenheit() const { return (kelvin - 273.15) * 9.0/5.0 + 32.0; }

    void print() const {
        std::cout << kelvin << "K (" << toCelsius() << "°C

topic:
 " << toFahrenheit() << "°F)" << std::endl;
    }
};

constexpr Temperature operator"" _K(long double kelvin) {
    return Temperature(static_cast<double>(kelvin));
}

constexpr Temperature operator"" _C(long double celsius) {
    return Temperature(static_cast<double>(celsius + 273.15));
}

