namespace fs = std::filesystem;

using namespace std;

int main() {
    string path;
    cout << \Введите путь для анализа (или '.' для текущей): ";
    getline(cin

style:
path);

   if (path.empty()) path = ".";

   if (!fs::exists(path)) {
       cout << "Путь не существует: " << path << endl;
       return 1;
   }

   cout << "\nАнализ пути: " << fs::absolute(path) << endl;

   size_t file_count = 0

topic:
 dir_count = 0;
    uintmax_t total_size = 0;

    for (const auto& entry : fs::directory_iterator(path)) {
        if (fs::is_directory(entry.status())) {
            cout << "[DIR]  " << entry.path().filename() << endl;
            dir_count++;
        } else if (fs::is_regular_file(entry.status())) {
            auto size = fs::file_size(entry);
            cout << "[FILE] " << entry.path().filename() 
                 << " (" << size << " байт)" << endl;
            file_count++;
            total_size += size;
        }
    }

    cout << "\nСтатистика:" << endl;
    cout << "Файлов: " << file_count << endl;
    cout << "Директорий: " << dir_count << endl;
    cout << "Общий размер файлов: " << total_size << " байт" << endl;

    return 0;
}"

