                 << " (" << size << " байт)" << std::endl;
            file_count++;
            total_size += size;
        }
    }

    std::cout << "\nСтатистика:" << std::endl;
    std::cout << "Файлов: " << file_count << std::endl;
    std::cout << "Директорий: " << dir_count << std::endl;
    std::cout << "Общий размер файлов: " << total_size << " байт" << std::endl;

    return 0;
}"

