#include <iterator>
#include <vector>
#include <string>
using namespace std;

class DataMover {
 vector<string> data;
public:
 void addData(string value) {
 data.push_back(move(value));
 }

 vector<string> extractData() {
 vector<string> result;
 result.insert(result.end(),
 make_move_iterator(data.begin()),
 make_move_iterator(data.end()));
 data.clear();
 return result;
 }

 template<typename InputIt>
 void moveData(InputIt first, InputIt last) {
 data.insert(data.end(),
 make_move_iterator(first),
 make_move_iterator(last));
 }
};

#include <iterator>
#include <vector>
