 data.push_back(std::move(value));
 }

 std::vector<std::string> extractData() {
 std::vector<std::string> result;
 result.insert(result.end(),
 std::make_move_iterator(data.begin()),
 std::make_move_iterator(data.end()));
 data.clear();
 return result;
 }

 template<typename InputIt>
 void moveData(InputIt first, InputIt last) {
 data.insert(data.end(),
 std::make_move_iterator(first),
 std::make_move_iterator(last));
 }
};

#include <iostream>
#include <utility>
using namespace std;

class Logger {
public:
    Logger() { cout << \Конструктор по умолчанию" << endl; }
    Logger(const Logger&) { cout << "Конструктор копирования" << endl; }
    Logger(Logger&&) { cout << "Конструктор перемещения" << endl; }
};

template<typename T>
void wrapper(T&& arg) {
    process(forward<T>(arg));
}

void process(Logger& log) {
    cout << "Обработка l-value" << endl;
}

void process(Logger&& log) {
    cout << "Обработка r-value" << endl;
}

int main() {
    Logger log1;
    wrapper(log1); // l-value
    wrapper(Logger()); // r-value

    return 0;
}"

