#include <iostream>
#include <memory>
#include <string>
using namespace std;

class Resource {
 string name;
public:
 Resource(string n) : name(n) { cout << \Resource " << name << " created" << endl; }
 ~Resource() { cout << "Resource " << name << " destroyed" << endl; }
 void use() { cout << "Using resource " << name << endl; }
};

class Manager {
 unique_ptr<Resource> resource;
public:
 Manager(string name) : resource(make_unique<Resource>(name)) {}
 void work() {
 if(resource) resource->use();
 }
};

int main() {
 Manager mgr("Database");
 mgr.work();
 return 0;
}"

