#include <iostream>
#include <memory>
using namespace std;

class MyClass {
public:
    MyClass(int value) : data(value) {
        cout << \MyClass constructed with " << data << endl;
    }

    ~MyClass() {
        cout << "MyClass destroyed with " << data << endl;
    }

    void print() {
        cout << "Data: " << data << endl;
    }

private:
    int data;
};

int main() {
    // unique_ptr
    unique_ptr<MyClass> ptr1 = make_unique<MyClass>(42);
    ptr1->print();

    // shared_ptr
    shared_ptr<MyClass> ptr2 = make_shared<MyClass>(100);
    shared_ptr<MyClass> ptr3 = ptr2;
    cout << "Shared count: " << ptr2.use_count() << endl;

    // weak_ptr
    weak_ptr<MyClass> weakPtr = ptr2;
    if (auto shared = weakPtr.lock()) {
        shared->print();
    }

    return 0;
}"

