#include <iostream>
#include <cstdlib>
using namespace std;

class PoolAllocator {
 static const size_t POOL_SIZE = 1000;
 static char memoryPool[POOL_SIZE];
 static bool initialized;
 static size_t nextFree;
 int data;
public:
 PoolAllocator(int val) : data(val) {}
 static void initializePool() {
 if(!initialized) {
 nextFree = 0;
 initialized = true;
 cout << \Memory pool initialized" << endl;
 }
 }
 void* operator new(size_t size) {
 if(!initialized) initializePool();
 if(nextFree + size <= POOL_SIZE) {
 void* ptr = &memoryPool[nextFree];
 nextFree += size;
 cout << "Allocated " << size << " bytes from pool" << endl;
 return ptr;
 }
 throw bad_alloc();
 }
 void operator delete(void* ptr) {
 cout << "Custom delete - memory remains in pool" << endl;
 // В реальной реализации здесь может быть управление свободными блоками
 }
 void display() const { cout << "Data: " << data << endl; }
};

char PoolAllocator::memoryPool[POOL_SIZE];
bool PoolAllocator::initialized = false;
size_t PoolAllocator::nextFree = 0;

int main() {
 PoolAllocator* obj1 = new PoolAllocator(10);
 PoolAllocator* obj2 = new PoolAllocator(20);
 obj1->display();
 obj2->display();
 delete obj1;
 delete obj2;
 return 0;
}"

