    consoleService.doWork();

    auto fileService = Service<FileLogger>(std::make_unique<FileLogger>());
    fileService.doWork();

    return 0;
}"

#include <iostream>
#include <unordered_map>
#include <list>
using namespace std;

class LRUCache {
private:
    int capacity;
    list<pair<int, int>> cache;
    unordered_map<int, list<pair<int, int>>::iterator> map;

public:
    LRUCache(int cap) : capacity(cap) {}

    int get(int key) {
        if (map.find(key) == map.end()) {
            return -1;
        }

        // Перемещаем в начало
        cache.splice(cache.begin(), cache, map[key]);
        return map[key]->second;
    }

    void put(int key, int value) {
        if (map.find(key) != map.end()) {
            // Обновляем значение и перемещаем в начало
            map[key]->second = value;
            cache.splice(cache.begin(), cache, map[key]);
            return;
        }

        if (cache.size() == capacity) {
            // Удаляем самый старый элемент
            int lastKey = cache.back().first;
            cache.pop_back();
            map.erase(lastKey);
        }

        // Добавляем новый элемент
        cache.emplace_front(key, value);
        map[key] = cache.begin();
    }
};

int main() {
    LRUCache cache(2);

    cache.put(1, 1);
    cache.put(2, 2);
    cout << \get(1): " << cache.get(1) << endl; // 1

    cache.put(3

topic:
 4); // Удаляет ключ 1
    cout << "get(1): " << cache.get(1) << endl; // -1
    cout << "get(3): " << cache.get(3) << endl; // 3
    cout << "get(4): " << cache.get(4) << endl; // 4

    return 0;
}"

