#include <iostream>
#include <fstream>
#include <string>
#include <vector>

class FileReader {
private:
    std::ifstream file;
    std::string filename;

public:
    explicit FileReader(const std::string& name) : filename(name) {
        file.open(filename);
        if (!file.is_open()) {
            throw std::runtime_error(\Не удалось открыть файл: " + filename);
        }
        std::cout << "Файл открыт: " << filename << std::endl;
    }

    ~FileReader() {
        if (file.is_open()) {
            file.close();
            std::cout << "Файл закрыт: " << filename << std::endl;
        }
    }

    std::vector<std::string> readAllLines() {
        std::vector<std::string> lines;
        std::string line;
        while (std::getline(file

style:
 line)) {
            lines.push_back(line);
        }
        return lines;
    }

    bool hasMoreLines() const {
        return !file.eof();
    }

    // Запрещаем копирование
    FileReader(const FileReader&) = delete;
    FileReader& operator=(const FileReader&) = delete;

    // Разрешаем перемещение
    FileReader(FileReader&&) = default;
    FileReader& operator=(FileReader&&) = default;
};

int main() {
    try {
        FileReader reader("output.txt");
        auto lines = reader.readAllLines();

        std::cout << "\nПрочитано строк: " << lines.size() << std::endl;
        for (size_t i = 0; i < lines.size(); ++i) {
            std::cout << "  " << i + 1 << ": " << lines[i] << std::endl;
        }

    } catch (const std::exception& e) {
        std::cout << "Ошибка: " << e.what() << std::endl;
    }

    return 0;
}"

