#include <iostream>
#include <cmath>
using namespace std;

double expTaylor(double x, int terms = 10) {
    double result = 1.0; // первый член ряда
    double term = 1.0;

    for (int i = 1; i <= terms; i++) {
        term *= x / i;
        result += term;
    }

    return result;
}

int main() {
    double x = 1.0;
    cout << \exp(" << x << ") = " << expTaylor(x) << endl;
    cout << "Проверка: " << exp(x) << endl;
    return 0;
}"

