#include <iostream>
#include <cmath>
using namespace std;

double lnTaylor(double x, int terms = 20) {
    if (x <= 0) return -1; // ошибка

    // Используем ряд для ln((1+y)/(1-y))
    double y = (x - 1) / (x + 1);
    double result = 0;

    for (int i = 0; i < terms; i++) {
        int n = 2 * i + 1;
        result += pow(y, n) / n;
    }

    return 2 * result;
}

int main() {
    double x = 2.0;
    cout << \ln(" << x << ") = " << lnTaylor(x) << endl;
    cout << "Проверка: " << log(x) << endl;
    return 0;
}"

