#include <iostream>
#include <cmath>
using namespace std;

double f(double x) {
    return x*x - 4; // x^2 - 4 = 0
}

double df(double x) {
    return 2*x; // производная
}

double newton(double x0, int max_iter = 100) {
    double x = x0;
    for(int i = 0; i < max_iter; i++) {
        x = x - f(x) / df(x);
        if(abs(f(x)) < 1e-10) break;
    }
    return x;
}

int main() {
    double root = newton(3.0);
    cout << \Корень: " << root << endl;
    return 0;
}"

