#include <iostream>
#include <vector>
using namespace std;

void sieveOfEratosthenes(int n) {
    vector<bool> isPrime(n+1, true);

    for(int p = 2; p*p <= n; p++) {
        if(isPrime[p]) {
            for(int i = p*p; i <= n; i += p) {
                isPrime[i] = false;
            }
        }
    }

    cout << \Простые числа до " << n << ": ";
    for(int p = 2; p <= n; p++) {
        if(isPrime[p]) cout << p << " ";
    }
    cout << endl;
}

int main() {
    sieveOfEratosthenes(30);
    return 0;
}"

