#include <iostream>
#include <string>
using namespace std;

bool luhnCheck(const string& cardNumber) {
    int sum = 0;
    bool alternate = false;

    for(int i = cardNumber.length() - 1; i >= 0; i--) {
        int digit = cardNumber[i] - '0';

        if(alternate) {
            digit *= 2;
            if(digit > 9) digit -= 9;
        }

        sum += digit;
        alternate = !alternate;
    }

    return (sum % 10 == 0);
}

int main() {
    string card = \4111111111111111";
    cout << "Карта " << (luhnCheck(card) ? "валидна" : "невалидна") << endl;
    return 0;
}"

