#include <iostream>
#include <vector>
#include <stack>
using namespace std;

struct TreeNode {
    int val;
    vector<TreeNode*> children;
    TreeNode(int x) : val(x) {}
};

void dfs(TreeNode* root) {
    if (!root) return;

    stack<TreeNode*> st;
    st.push(root);

    while (!st.empty()) {
        TreeNode* node = st.top();
        st.pop();

        cout << node->val << \ ";

        // Добавляем детей в обратном порядке для правильного обхода
        for (auto it = node->children.rbegin(); it != node->children.rend(); ++it) {
            st.push(*it);
        }
    }
}

int main() {
    TreeNode* root = new TreeNode(1);
    root->children.push_back(new TreeNode(2));
    root->children.push_back(new TreeNode(3));
    root->children[0]->children.push_back(new TreeNode(4));
    root->children[0]->children.push_back(new TreeNode(5));
    root->children[1]->children.push_back(new TreeNode(6));

    cout << "DFS обход: ";
    dfs(root);
    cout << endl;

    return 0;
}"

