#include <iostream>
#include <vector>
#include <stack>
using namespace std;

void topologicalSortUtil(int v, const vector<vector<int>>& graph, 
                        vector<bool>& visited, stack<int>& stack) {
    visited[v] = true;

    for (int neighbor : graph[v]) {
        if (!visited[neighbor]) {
            topologicalSortUtil(neighbor, graph, visited, stack);
        }
    }

    stack.push(v);
}

vector<int> topologicalSort(const vector<vector<int>>& graph) {
    int n = graph.size();
    vector<bool> visited(n, false);
    stack<int> stack;

    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            topologicalSortUtil(i, graph, visited, stack);
        }
    }

    vector<int> result;
    while (!stack.empty()) {
        result.push_back(stack.top());
        stack.pop();
    }

    return result;
}

int main() {
    int n = 6;
    vector<vector<int>> graph(n);

    // Граф зависимостей
    graph[5].push_back(2);
    graph[5].push_back(0);
    graph[4].push_back(0);
    graph[4].push_back(1);
    graph[2].push_back(3);
    graph[3].push_back(1);

    vector<int> sorted = topologicalSort(graph);

    cout << \Топологическая сортировка:" << endl;
    for (int node : sorted) {
        cout << node << " ";
    }
    cout << endl;

    return 0;
}"

