#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

void findBridgesUtil(int u, const vector<vector<int>>& graph, vector<bool>& visited, 
                    vector<int>& disc, vector<int>& low, vector<int>& parent, 
                    vector<pair<int, int>>& bridges, int& time) {
    visited[u] = true;
    disc[u] = low[u] = ++time;

    for (int v : graph[u]) {
        if (!visited[v]) {
            parent[v] = u;
            findBridgesUtil(v, graph, visited, disc, low, parent, bridges, time);

            low[u] = min(low[u], low[v]);

            if (low[v] > disc[u]) {
                bridges.push_back({u, v});
            }
        } else if (v != parent[u]) {
            low[u] = min(low[u], disc[v]);
        }
    }
}

vector<pair<int, int>> findBridges(const vector<vector<int>>& graph) {
    int n = graph.size();
    vector<bool> visited(n, false);
    vector<int> disc(n, -1);
    vector<int> low(n, -1);
    vector<int> parent(n, -1);
    vector<pair<int, int>> bridges;
    int time = 0;

    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            findBridgesUtil(i, graph, visited, disc, low, parent, bridges, time);
        }
    }

    return bridges;
}

int main() {
    int n = 5;
    vector<vector<int>> graph(n);

    graph[0] = {1, 2};
    graph[1] = {0, 2};
    graph[2] = {0, 1, 3, 4};
    graph[3] = {2, 4};
    graph[4] = {2, 3};

    vector<pair<int, int>> bridges = findBridges(graph);

    cout << \Мосты в графе:" << endl;
    for (auto& bridge : bridges) {
        cout << bridge.first << " - " << bridge.second << endl;
    }

    return 0;
}"

#include <iostream>
#include <vector>
#include <algorithm>

void findBridgesUtil(int u, const std::vector<std::vector<int>>& graph, std::vector<bool>& visited, 
                    std::vector<int>& disc, std::vector<int>& low, std::vector<int>& parent, 
                    std::vector<std::pair<int, int>>& bridges, int& time) {
    visited[u] = true;
    disc[u] = low[u] = ++time;

    for (int v : graph[u]) {
        if (!visited[v]) {
            parent[v] = u;
            findBridgesUtil(v, graph, visited, disc, low, parent, bridges, time);

            low[u] = std::min(low[u], low[v]);

            if (low[v] > disc[u]) {
                bridges.push_back({u, v});
            }
        } else if (v != parent[u]) {
            low[u] = std::min(low[u], disc[v]);
        }
    }
}

std::vector<std::pair<int, int>> findBridges(const std::vector<std::vector<int>>& graph) {
    int n = graph.size();
    std::vector<bool> visited(n, false);
    std::vector<int> disc(n, -1);
    std::vector<int> low(n, -1);
    std::vector<int> parent(n, -1);
    std::vector<std::pair<int, int>> bridges;
    int time = 0;

    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            findBridgesUtil(i, graph, visited, disc, low, parent, bridges, time);
        }
    }

    return bridges;
}

int main() {
    int n = 5;
    std::vector<std::vector<int>> graph(n);

    graph[0] = {1, 2};
    graph[1] = {0, 2};
    graph[2] = {0, 1, 3, 4};
    graph[3] = {2, 4};
    graph[4] = {2, 3};

    std::vector<std::pair<int, int>> bridges = findBridges(graph);

    std::cout << \Мосты в графе:" << std::endl;
    for (auto& bridge : bridges) {
        std::cout << bridge.first << " - " << bridge.second << std::endl;
    }

    return 0;
}"

#include <iostream>
#include <vector>
#include <stack>
#include <algorithm>
using namespace std;

void fillOrder(int v, const vector<vector<int>>& graph, vector<bool>& visited, stack<int>& stack) {
    visited[v] = true;

    for (int neighbor : graph[v]) {
        if (!visited[neighbor]) {
            fillOrder(neighbor, graph, visited, stack);
        }
    }

    stack.push(v);
}

void DFSUtil(int v, const vector<vector<int>>& graph, vector<bool>& visited, vector<int>& component) {
    visited[v] = true;
    component.push_back(v);

    for (int neighbor : graph[v]) {
        if (!visited[neighbor]) {
            DFSUtil(neighbor, graph, visited, component);
        }
    }
}

vector<vector<int>> findSCCs(const vector<vector<int>>& graph) {
    int n = graph.size();
    vector<bool> visited(n, false);
    stack<int> stack;

    // Первый проход DFS для заполнения стека
    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            fillOrder(i, graph, visited, stack);
        }
    }

    // Транспонирование графа
    vector<vector<int>> transposed(n);
    for (int u = 0; u < n; u++) {
        for (int v : graph[u]) {
            transposed[v].push_back(u);
        }
    }

    // Второй проход DFS на транспонированном графе
    fill(visited.begin(), visited.end(), false);
    vector<vector<int>> sccs;

    while (!stack.empty()) {
        int v = stack.top();
        stack.pop();

        if (!visited[v]) {
            vector<int> component;
            DFSUtil(v, transposed, visited, component);
            sccs.push_back(component);
        }
    }

    return sccs;
}

int main() {
    int n = 5;
    vector<vector<int>> graph(n);

    graph[0] = {1};
    graph[1] = {2};
    graph[2] = {0, 3};
    graph[3] = {4};

    vector<vector<int>> sccs = findSCCs(graph);

    cout << \Сильно связные компоненты:" << endl;
    for (size_t i = 0; i < sccs.size(); i++) {
        cout << "Компонента " << i + 1 << ": ";
        for (int node : sccs[i]) {
            cout << node << " ";
        }
        cout << endl;
    }

    return 0;
}"

