            pos++;
        }
    }

    double parse_expression();
    double parse_term();
    double parse_factor();

public:
    Parser(const std::string& str) : input(str), pos(0) {
        // Пропускаем начальные пробелы
        while (pos < input.length() && std::isspace(input[pos])) {
            pos++;
        }
    }

    double parse() {
        return parse_expression();
    }
};

double Parser::parse_expression() {
    double result = parse_term();

    while (current_char() == '+' || current_char() == '-') {
        char op = current_char();
        advance();
        double term = parse_term();

        if (op == '+') {
            result += term;
        } else {
            result -= term;
        }
    }

    return result;
}

double Parser::parse_term() {
    double result = parse_factor();

    while (current_char() == '*' || current_char() == '/') {
        char op = current_char();
        advance();
        double factor = parse_factor();

        if (op == '*') {
            result *= factor;
        } else {
            if (factor == 0) {
                throw std::runtime_error(\Деление на ноль");
            }
            result /= factor;
        }
    }

    return result;
}

double Parser::parse_factor() {
    if (current_char() == '(') {
        advance(); // пропускаем '('
        double result = parse_expression();
        if (current_char() != ')') {
            throw std::runtime_error("Ожидается ')'");
        }
        advance(); // пропускаем ')'
        return result;
    }

    if (std::isdigit(current_char()) || current_char() == '.') {
        std::string number;
        while (std::isdigit(current_char()) || current_char() == '.') {
            number += current_char();
            advance();
        }
        return std::stod(number);
    }

    throw std::runtime_error("Неожиданный символ: " + std::string(1

style:
 current_char()));
}

