using namespace std;

struct Vector2 {
    double x, y;

    Vector2(double x = 0, double y = 0) : x(x), y(y) {}

    Vector2 operator+(const Vector2& other) const {
        return Vector2(x + other.x, y + other.y);
    }

    Vector2 operator-(const Vector2& other) const {
        return Vector2(x - other.x, y - other.y);
    }

    Vector2 operator*(double scalar) const {
        return Vector2(x * scalar, y * scalar);
    }

    double length() const {
        return sqrt(x * x + y * y);
    }

    Vector2 normalized() const {
        double len = length();
        if (len > 0) {
            return Vector2(x / len, y / len);
        }
        return *this;
    }
};

class Particle {
public:
    Vector2 position;
    Vector2 velocity;
    Vector2 acceleration;
    double mass;
    double lifetime;
    double age;

    Particle(Vector2 pos, Vector2 vel, double m = 1.0, double life = 5.0) 
        : position(pos), velocity(vel), acceleration(0, 0), 
          mass(m), lifetime(life), age(0) {}

    void update(double dt) {
        velocity = velocity + acceleration * dt;
        position = position + velocity * dt;
        acceleration = Vector2(0, 0); // сбрасываем ускорение
        age += dt;
    }

    void applyForce(const Vector2& force) {
        acceleration = acceleration + force * (1.0 / mass);
    }

    bool isDead() const {
        return age >= lifetime;
    }
};

class ParticleSystem {
private:
    vector<unique_ptr<Particle>> particles;
    Vector2 gravity;
    double width, height;

    random_device rd;
    mt19937 gen;
    uniform_real_distribution<> dis;

public:
    ParticleSystem(double w = 800, double h = 600) 
        : gravity(0, 98), width(w), height(h), gen(rd()), dis(-1.0, 1.0) {}

    void addParticle(Vector2 position) {
        Vector2 velocity(dis(gen) * 50, dis(gen) * 50 - 100);
        auto particle = make_unique<Particle>(position, velocity, 1.0, 3.0 + dis(gen) * 2.0);
        particles.push_back(move(particle));
    }

    void update(double dt) {
        // Обновляем частицы и применяем физику
        for (auto& particle : particles) {
            // Гравитация
            particle->applyForce(gravity * particle->mass);

            // Сопротивление воздуха
            Vector2 drag = particle->velocity.normalized() * -0.1 * particle->velocity.length() * particle->velocity.length();
            particle->applyForce(drag);

            particle->update(dt);

            // Отскок от границ
            if (particle->position.x < 0 || particle->position.x > width) {
                particle->velocity.x *= -0.8;
                particle->position.x = max(0.0, min(width, particle->position.x));
            }

            if (particle->position.y < 0 || particle->position.y > height) {
                particle->velocity.y *= -0.8;
                particle->position.y = max(0.0, min(height, particle->position.y));
            }
        }

        // Удаляем мертвые частицы
        particles.erase(
            remove_if(particles.begin(), particles.end(), 
                     [](const unique_ptr<Particle>& p) { return p->isDead(); }),
            particles.end()
        );
    }

    void draw() {
        cout << \Частиц: " << particles.size() << endl;
        for (const auto& particle : particles) {
            cout << "Particle at (" << particle->position.x << "

style:
 " 
                 << particle->position.y << ") age: " << particle->age << endl;
        }
        cout << "---" << endl;
    }

    size_t getParticleCount() const {
        return particles.size();
    }
};

