#include <iostream>
#include <vector>
#include <cmath>
#include <limits>
#include <memory>
#include <algorithm>
using namespace std;

struct Vector3 {
    double x, y, z;

    Vector3(double x = 0, double y = 0, double z = 0) : x(x), y(y), z(z) {}

    Vector3 operator+(const Vector3& other) const {
        return Vector3(x + other.x, y + other.y, z + other.z);
    }

    Vector3 operator-(const Vector3& other) const {
        return Vector3(x - other.x, y - other.y, z - other.z);
    }

    Vector3 operator*(double scalar) const {
        return Vector3(x * scalar, y * scalar, z * scalar);
    }

    double dot(const Vector3& other) const {
        return x * other.x + y * other.y + z * other.z;
    }

    Vector3 cross(const Vector3& other) const {
        return Vector3(y * other.z - z * other.y,
                      z * other.x - x * other.z,
                      x * other.y - y * other.x);
    }

    double length() const {
        return sqrt(x * x + y * y + z * z);
    }

    Vector3 normalized() const {
        double len = length();
        if (len > 0) {
            return Vector3(x / len, y / len, z / len);
        }
        return *this;
    }
};

struct Ray {
    Vector3 origin;
    Vector3 direction;

    Ray(const Vector3& o, const Vector3& d) : origin(o), direction(d.normalized()) {}

    Vector3 pointAt(double t) const {
        return origin + direction * t;
    }
};

struct Material {
    Vector3 color;
    double reflectivity;
    double transparency;

    Material(const Vector3& c = Vector3(1, 1, 1), double r = 0, double t = 0) 
        : color(c), reflectivity(r), transparency(t) {}
};

struct HitRecord {
    double t;
    Vector3 point;
    Vector3 normal;
    Material material;

    HitRecord() : t(numeric_limits<double>::max()) {}
};

class Sphere {
public:
    Vector3 center;
    double radius;
    Material material;

    Sphere(const Vector3& c, double r, const Material& m) 
        : center(c), radius(r), material(m) {}

    bool intersect(const Ray& ray, HitRecord& rec) const {
        Vector3 oc = ray.origin - center;
        double a = ray.direction.dot(ray.direction);
        double b = 2.0 * oc.dot(ray.direction);
        double c = oc.dot(oc) - radius * radius;

        double discriminant = b * b - 4 * a * c;

        if (discriminant < 0) {
            return false;
        }

        double sqrt_d = sqrt(discriminant);
        double t1 = (-b - sqrt_d) / (2.0 * a);
        double t2 = (-b + sqrt_d) / (2.0 * a);

        double t = min(t1, t2);
        if (t < 0) {
            t = max(t1, t2);
        }

        if (t > 0 && t < rec.t) {
            rec.t = t;
            rec.point = ray.pointAt(t);
            rec.normal = (rec.point - center).normalized();
            rec.material = material;
            return true;
        }

        return false;
    }
};

class Scene {
private:
    vector<Sphere> spheres;

public:
    void addSphere(const Sphere& sphere) {
        spheres.push_back(sphere);
    }

    bool intersect(const Ray& ray, HitRecord& rec) const {
        bool hit_anything = false;

        for (const auto& sphere : spheres) {
            if (sphere.intersect(ray, rec)) {
                hit_anything = true;
            }
        }

        return hit_anything;
    }
};

Vector3 traceRay(const Ray& ray, const Scene& scene, int depth = 0) {
    if (depth > 5) {
        return Vector3(0, 0, 0); // ограничение глубины рекурсии
    }

    HitRecord rec;
    if (scene.intersect(ray, rec)) {
        // Простое затенение
        Vector3 light_dir = Vector3(1, 1, 1).normalized();
        double diffuse = max(0.0, rec.normal.dot(light_dir));

        Vector3 color = rec.material.color * diffuse;

        // Добавляем ambient
        color = color + Vector3(0.1, 0.1, 0.1);

        return color;
    }

    // Фон
    return Vector3(0.2, 0.2, 0.8);
}

